  // ─── 17. RIGHT TRIANGLE TRIG RATIOS ───────────────────────────────────────
  // Classic SOH-CAH-TOA diagram:
  //   • right triangle with angle θ, right-angle marker
  //   • sides labelled: Opposite, Adjacent, Hypotenuse
  //   • sin θ = O/H, cos θ = A/H, tan θ = O/A
  //   • mnemonic SOH-CAH-TOA
  static rightTriangleTrigRatiosDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 500 420">

  <!-- Title -->
  <text x="80" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Right Triangle — Trigonometric Ratios (SOH-CAH-TOA)</text>

  <!-- ══ TRIANGLE ══
       Right angle at R=(120,330)
       A = top (120,110) — vertical leg = Opposite
       B = right (380,330) — horizontal leg = Adjacent
       Hypotenuse A to B
  ══ -->

  <!-- Triangle -->
  <polygon points="120,110 120,330 380,330"
           fill="none" stroke="#000" stroke-width="5" stroke-linejoin="round"/>

  <!-- Right angle marker at R -->
  <rect x="120" y="310" width="22" height="22" fill="none" stroke="#000" stroke-width="3"/>

  <!-- Angle θ arc at B=(380,330) -->
  <path d="M360,330 A20,20 0 0,0 367,313" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="342" y="318" font-family="Georgia,serif" font-size="16" font-weight="bold" font-style="italic" fill="#000">θ</text>

  <!-- Side labels -->
  <!-- Opposite (vertical): midpoint (120,220) → label left -->
  <text x="20" y="228" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">Opposite</text>
  <text x="42" y="244" font-family="Georgia,serif" font-size="11" fill="#555">(O)</text>
  <line x1="76" y1="236" x2="112" y2="236" stroke="#000" stroke-width="1.5" stroke-dasharray="4,3"/>

  <!-- Adjacent (horizontal): midpoint (250,330) → label below -->
  <text x="218" y="358" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">Adjacent (A)</text>

  <!-- Hypotenuse: midpoint ~(250,220) → label right, perpendicular -->
  <text x="262" y="208" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">Hypotenuse</text>
  <text x="284" y="224" font-family="Georgia,serif" font-size="11" fill="#555">(H)</text>

  <!-- Vertex dots -->
  <circle cx="120" cy="110" r="5" fill="#000"/>
  <circle cx="120" cy="330" r="5" fill="#000"/>
  <circle cx="380" cy="330" r="5" fill="#000"/>

  <!-- ══ RATIO TABLE ══ -->
  <rect x="60" y="375" width="380" height="38" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="74" y="393" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">sin θ = O/H</text>
  <line x1="190" y1="376" x2="190" y2="413" stroke="#000" stroke-width="1.5"/>
  <text x="204" y="393" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">cos θ = A/H</text>
  <line x1="318" y1="376" x2="318" y2="413" stroke="#000" stroke-width="1.5"/>
  <text x="330" y="393" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">tan θ = O/A</text>
  <text x="74" y="408" font-family="Georgia,serif" font-size="10" fill="#555">SOH</text>
  <text x="204" y="408" font-family="Georgia,serif" font-size="10" fill="#555">CAH</text>
  <text x="330" y="408" font-family="Georgia,serif" font-size="10" fill="#555">TOA</text>

  <!-- Mnemonic banner -->
  <text x="250" y="130" font-family="Georgia,serif" font-size="20" font-weight="bold" fill="#000" text-anchor="middle">SOH-CAH-TOA</text>

  <!-- Reciprocal ratios note -->
  <text x="250" y="155" font-family="Georgia,serif" font-size="10" fill="#555" text-anchor="middle">cosec θ = H/O  |  sec θ = H/A  |  cot θ = A/O</text>
</svg>`;

