  // ─── 19. TRIG IDENTITIES VISUAL ───────────────────────────────────────────
  // Shows the major trig identities geometrically/algebraically:
  //   • Pythagorean: sin²θ + cos²θ = 1 shown on unit circle triangle
  //   • Double angle formulas
  //   • Sum formulas
  //   • All set in a structured diagram panel
  static trigIdentitiesVisualDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 480">

  <!-- Title -->
  <text x="80" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Trigonometric Identities — Visual Reference</text>

  <!-- ══ PYTHAGOREAN IDENTITY — unit circle triangle (left) ══ -->
  <text x="30" y="55" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">1. Pythagorean Identity</text>

  <!-- Unit circle -->
  <circle cx="110" cy="175" r="90" fill="none" stroke="#000" stroke-width="2.5"/>
  <!-- Axes -->
  <line x1="18" y1="175" x2="202" y2="175" stroke="#000" stroke-width="1.8"/>
  <line x1="110" y1="85" x2="110" y2="265" stroke="#000" stroke-width="1.8"/>

  <!-- Point P at 50°: cos50≈0.643, sin50≈0.766 → (168,107) -->
  <line x1="110" y1="175" x2="168" y2="107" stroke="#000" stroke-width="3"/>
  <line x1="168" y1="175" x2="168" y2="107" stroke="#000" stroke-width="3"/>
  <line x1="110" y1="175" x2="168" y2="175" stroke="#000" stroke-width="3"/>
  <!-- right angle marker -->
  <rect x="158" y="165" width="10" height="10" fill="none" stroke="#000" stroke-width="2"/>
  <!-- r=1 label on hypotenuse -->
  <text x="132" y="136" font-family="Georgia,serif" font-size="12" font-style="italic" fill="#000">1</text>
  <!-- cos θ label -->
  <text x="130" y="192" font-family="Georgia,serif" font-size="11" font-style="italic" fill="#000">cos θ</text>
  <!-- sin θ label -->
  <text x="172" y="145" font-family="Georgia,serif" font-size="11" font-style="italic" fill="#000">sin θ</text>
  <!-- P dot -->
  <circle cx="168" cy="107" r="4" fill="#000"/>
  <!-- θ arc -->
  <path d="M136,175 A26,26 0 0,0 127,151" fill="none" stroke="#000" stroke-width="2"/>
  <text x="136" y="164" font-family="Georgia,serif" font-size="11" font-style="italic" fill="#000">θ</text>

  <!-- Identity label -->
  <rect x="18" y="272" width="184" height="28" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="28" y="290" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">sin²θ + cos²θ  =  1</text>

  <!-- ══ IDENTITIES PANEL (right column) ══ -->

  <!-- 2. Sum / Difference -->
  <rect x="228" y="44" width="280" height="100" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="238" y="64" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">2. Sum &amp; Difference Formulas</text>
  <text x="238" y="82" font-family="Georgia,serif" font-size="11" fill="#000">sin(A±B) = sinA cosB ± cosA sinB</text>
  <text x="238" y="100" font-family="Georgia,serif" font-size="11" fill="#000">cos(A±B) = cosA cosB ∓ sinA sinB</text>
  <text x="238" y="118" font-family="Georgia,serif" font-size="11" fill="#000">tan(A±B) = (tanA ± tanB)/(1 ∓ tanA tanB)</text>
  <text x="238" y="136" font-family="Georgia,serif" font-size="9" fill="#555">upper signs → addition;  lower signs → subtraction</text>

  <!-- 3. Double Angle -->
  <rect x="228" y="158" width="280" height="90" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="238" y="178" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">3. Double Angle Formulas</text>
  <text x="238" y="196" font-family="Georgia,serif" font-size="11" fill="#000">sin 2θ = 2 sinθ cosθ</text>
  <text x="238" y="214" font-family="Georgia,serif" font-size="11" fill="#000">cos 2θ = cos²θ − sin²θ  =  2cos²θ−1  =  1−2sin²θ</text>
  <text x="238" y="232" font-family="Georgia,serif" font-size="11" fill="#000">tan 2θ = 2 tanθ / (1 − tan²θ)</text>

  <!-- 4. Pythagorean family -->
  <rect x="228" y="262" width="280" height="80" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="238" y="282" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">4. Pythagorean Family</text>
  <text x="238" y="300" font-family="Georgia,serif" font-size="11" fill="#000">sin²θ + cos²θ = 1</text>
  <text x="238" y="318" font-family="Georgia,serif" font-size="11" fill="#000">1 + tan²θ = sec²θ</text>
  <text x="238" y="336" font-family="Georgia,serif" font-size="11" fill="#000">1 + cot²θ = cosec²θ</text>

  <!-- 5. Reciprocal identities -->
  <rect x="228" y="356" width="280" height="80" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="238" y="376" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">5. Reciprocal Identities</text>
  <text x="238" y="394" font-family="Georgia,serif" font-size="11" fill="#000">cosec θ = 1/sinθ   sec θ = 1/cosθ   cot θ = 1/tanθ</text>
  <text x="238" y="412" font-family="Georgia,serif" font-size="11" fill="#000">tan θ = sinθ/cosθ   cot θ = cosθ/sinθ</text>
  <text x="238" y="428" font-family="Georgia,serif" font-size="9" fill="#555">Defined where denominator ≠ 0</text>

  <!-- Left column bottom: co-function identities -->
  <rect x="18" y="316" width="190" height="80" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="28" y="334" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">6. Co-function</text>
  <text x="28" y="352" font-family="Georgia,serif" font-size="11" fill="#000">sin(90°−θ) = cosθ</text>
  <text x="28" y="368" font-family="Georgia,serif" font-size="11" fill="#000">cos(90°−θ) = sinθ</text>
  <text x="28" y="384" font-family="Georgia,serif" font-size="11" fill="#000">tan(90°−θ) = cotθ</text>
  <text x="28" y="398" font-family="Georgia,serif" font-size="9" fill="#555">complementary angles</text>
</svg>`;

