  <!-- Altitude from B=(210,100) perpendicular to CA (horizontal y=310) → D=(210,310) -->
  <line x1="210" y1="100" x2="210" y2="310" stroke="#000" stroke-width="1.8" stroke-dasharray="5,4"/>
