  static regularPolygonApothemDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 500 480">

  <!-- Title -->
  <text x="70" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Regular Polygon Area: A = ½ × Perimeter × Apothem</text>
  <text x="100" y="38" font-family="Georgia,serif" font-size="10" fill="#444">Illustrated with a regular hexagon (n=6 sides)</text>

  <!-- Regular hexagon cx=250, cy=250, r=160
       Vertices at angles 0°,60°,120°,180°,240°,300° (point-up orientation, rotated 30° → flat-top):
       Using flat-top: angles 30°,90°,150°,210°,270°,330°
       V0=(250+160cos30°, 250-160sin30°)=(250+138.6,250-80)=(388.6,170)
       V1=(250+160cos90°,250-160sin90°)=(250,90)
       V2=(250+160cos150°,250-160sin150°)=(250-138.6,250-80)=(111.4,170)
       V3=(250+160cos210°,250-160sin210°)=(250-138.6,250+80)=(111.4,330)
       V4=(250+160cos270°,250-160sin270°)=(250,410)
       V5=(250+160cos330°,250-160sin330°)=(388.6,330)
  -->
  <polygon points="389,170 250,90 111,170 111,330 250,410 389,330"
           fill="none" stroke="#000" stroke-width="5" stroke-linejoin="round"/>

  <!-- Triangular sectors from centre -->
  <line x1="250" y1="250" x2="389" y2="170" stroke="#000" stroke-width="1.5" stroke-dasharray="5,4"/>
  <line x1="250" y1="250" x2="250" y2="90"  stroke="#000" stroke-width="1.5" stroke-dasharray="5,4"/>
  <line x1="250" y1="250" x2="111" y2="170" stroke="#000" stroke-width="1.5" stroke-dasharray="5,4"/>
  <line x1="250" y1="250" x2="111" y2="330" stroke="#000" stroke-width="1.5" stroke-dasharray="5,4"/>
  <line x1="250" y1="250" x2="250" y2="410" stroke="#000" stroke-width="1.5" stroke-dasharray="5,4"/>
  <line x1="250" y1="250" x2="389" y2="330" stroke="#000" stroke-width="1.5" stroke-dasharray="5,4"/>

  <!-- Centre dot -->
  <circle cx="250" cy="250" r="5" fill="#000"/>
  <text x="256" y="246" font-family="Georgia,serif" font-size="11" fill="#000">O</text>

  <!-- Circumradius R: from O to V0 -->
  <text x="310" y="204" font-family="Georgia,serif" font-size="14" font-weight="bold" font-style="italic" fill="#000">R</text>

  <!-- Apothem: perpendicular from O to midpoint of top-right side (V0V1)
       Midpoint of V0=(389,170) and V1=(250,90): mid=(319.5,130)
       Apothem length for regular hex = r × cos(30°) = 160×0.866=138.6
  -->
  <line x1="250" y1="250" x2="320" y2="130" stroke="#000" stroke-width="3"/>
  <!-- right angle at foot -->
  <rect x="313" y="124" width="14" height="14" fill="none" stroke="#000" stroke-width="2" transform="rotate(-30,320,130)"/>
  <text x="268" y="178" font-family="Georgia,serif" font-size="14" font-weight="bold" font-style="italic" fill="#000">a (apothem)</text>

  <!-- Side label s on bottom side -->
  <text x="242" y="428" font-family="Georgia,serif" font-size="14" font-weight="bold" font-style="italic" fill="#000">s</text>

  <!-- Formula box -->
  <rect x="50" y="438" width="400" height="34" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="62" y="451" font-family="Georgia,serif" font-size="12" fill="#000">P = n × s = 6s   |   A = ½ × P × a = ½ × 6s × a = 3sa</text>
  <text x="62" y="466" font-family="Georgia,serif" font-size="12" fill="#000">Also: a = R cos(π/n)   |   s = 2R sin(π/n)</text>
</svg>`;

  // ─── 13. COMPOSITE AREA ADD/SUBTRACT DIAGRAM ──────────────────────────────
  // An L-shape and a shape with a circular hole, showing how to compute area
