  <defs>
    <pattern id="hpy1" patternUnits="userSpaceOnUse" width="8" height="8" patternTransform="rotate(30)">
      <line x1="0" y1="0" x2="0" y2="8" stroke="#bbb" stroke-width="1"/>
    </pattern>
    <pattern id="hpy2" patternUnits="userSpaceOnUse" width="8" height="8" patternTransform="rotate(120)">
      <line x1="0" y1="0" x2="0" y2="8" stroke="#999" stroke-width="1.2"/>
    </pattern>
  </defs>

