  // ─── 21. INTERIOR ANGLE FROM BEARINGS DIAGRAM ─────────────────────────────
  static interiorAngleFromBearingsDiagramDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 500 460">

  <text x="80" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Interior Angle from Bearings</text>
  <text x="60" y="38" font-family="Georgia,serif" font-size="10" fill="#444">Finding the angle between two directions using their bearings</text>

  <!-- Vertex at B = (250,280) -->
  <!-- Ray BA: bearing from B to A = 320° (NW-ish)
       direction: (250+200·sin320°, 280−200·cos320°) = (250−128.6,280−153.2)=(121.4,126.8)≈(121,127) -->
  <!-- Ray BC: bearing from B to C = 070°
       direction: (250+200·sin70°, 280−200·cos70°) = (250+187.9,280−68.4)=(437.9,211.6)≈(438,212) -->

  <!-- North reference at B -->
  <line x1="250" y1="370" x2="250" y2="90" stroke="#000" stroke-width="1.5" stroke-dasharray="5,4"/>
  <polygon points="244,100 250,82 256,100" fill="#000"/>
  <text x="234" y="78" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">N</text>

  <!-- Ray BA -->
  <line x1="250" y1="280" x2="121" y2="127" stroke="#000" stroke-width="3.5"/>
  <polygon points="129,136 113,120 126,115" fill="#000"/>
  <text x="96" y="116" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">A</text>

  <!-- Ray BC -->
  <line x1="250" y1="280" x2="438" y2="212" stroke="#000" stroke-width="3.5"/>
  <polygon points="426,215 444,205 442,220" fill="#000"/>
  <text x="444" y="207" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">C</text>

  <!-- Bearing 320° arc at B (from N clockwise to BA) -->
  <path d="M 250,230 A 50,50 0 1,1 218,257" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="172" y="218" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">320°</text>

  <!-- Bearing 070° arc at B (from N clockwise to BC) -->
  <path d="M 250,230 A 50,50 0 0,1 297,247" fill="none" stroke="#000" stroke-width="2"/>
  <text x="272" y="222" font-family="Georgia,serif" font-size="11" fill="#000">070°</text>

  <!-- Interior angle ABC -->
  <!-- Angle from BA to BC = 070° − (320°−360°) = 070° + 040° = 110°
       Or: difference in bearings = |320−70|=250, interior = 360−250=110° -->
  <path d="M 214,256 A 40,40 0 0,1 287,260" fill="none" stroke="#000" stroke-width="3"/>
  <text x="232" y="254" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">110°</text>

  <!-- B vertex -->
  <circle cx="250" cy="280" r="7" fill="#000"/>
  <text x="225" y="296" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">B</text>

  <!-- Calculation box -->
  <rect x="40" y="360" width="420" height="80" rx="5" fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="5,3"/>
  <text x="52" y="380" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Method: Interior ∠ABC = bearing of BC − bearing of BA (back bearing)</text>
  <text x="52" y="398" font-family="Georgia,serif" font-size="11" fill="#000">Back bearing of BA from B = 320° − 180° = 140°</text>
  <text x="52" y="416" font-family="Georgia,serif" font-size="11" fill="#000">Interior angle = 140° − 070° = 110° (or use |diff| adjusted to 0°–180°)</text>
  <text x="52" y="432" font-family="Georgia,serif" font-size="10" fill="#000">Check: always take the angle inside the path of travel</text>
</svg>`;

  // ─── 22. BEARING LOCI AND INTERSECTION DIAGRAM ────────────────────────────
  static bearingLociAndIntersectionDiagramDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 500 460">

  <text x="70" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Bearing Loci — Intersection to Fix Position</text>
  <text x="60" y="38" font-family="Georgia,serif" font-size="10" fill="#444">Two bearing lines from known points intersect to locate unknown point P</text>

  <!-- Known point A at (120,340) -->
  <circle cx="120" cy="340" r="8" fill="#000"/>
  <text x="96" y="338" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">A</text>
  <!-- North at A -->
  <line x1="120" y1="355" x2="120" y2="80" stroke="#000" stroke-width="1.5" stroke-dasharray="5,4"/>
  <polygon points="114,90 120,72 126,90" fill="#000"/>
  <text x="104" y="68" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">N</text>

  <!-- Known point B at (380,340) -->
  <circle cx="380" cy="340" r="8" fill="#000"/>
  <text x="386" y="338" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">B</text>
  <!-- North at B -->
  <line x1="380" y1="355" x2="380" y2="80" stroke="#000" stroke-width="1.5" stroke-dasharray="5,4"/>
  <polygon points="374,90 380,72 386,90" fill="#000"/>
  <text x="364" y="68" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">N</text>

  <!-- Bearing from A = 050°: line from A(120,340) in direction 050°
       Extended: endpoint (120+400·sin50°, 340−400·cos50°)=(120+306,340−257)=(426,83) -->
  <line x1="120" y1="340" x2="426" y2="83" stroke="#000" stroke-width="2.5" stroke-dasharray="8,5"/>
  <!-- Bearing arc at A -->
  <path d="M 120,300 A 40,40 0 0,1 151,321" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="135" y="302" font-family="Georgia,serif" font-size="11" fill="#000">050°</text>

  <!-- Bearing from B = 330°: line from B(380,340) in direction 330°
       sin330=−0.5, cos330=0.866
       Endpoint: (380−200,340−173)=(180,167) -->
  <line x1="380" y1="340" x2="180" y2="167" stroke="#000" stroke-width="2.5" stroke-dasharray="8,5"/>
  <!-- Bearing arc at B (large clockwise 330°) -->
  <path d="M 380,300 A 40,40 0 1,1 360,321" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="320" y="296" font-family="Georgia,serif" font-size="11" fill="#000">330°</text>

  <!-- Intersection point P:
       From A bearing 050° passes through approx (278,193) based on geometry
       Let me use the actual intersection. Parametric:
       A+(t·sin50°, −t·cos50°) = B+(s·sin330°, −s·cos330°)
       120+0.766t = 380−0.5s  ... (i)
       340−0.643t = 340−0.866s ... (ii)
       from (ii): 0.643t = 0.866s → s = 0.742t
       sub in (i): 120+0.766t = 380−0.371t → 1.137t=260 → t=228.7
       P=(120+175.2, 340−147) = (295,193) -->
  <circle cx="295" cy="193" r="9" fill="#fff" stroke="#000" stroke-width="3.5"/>
  <circle cx="295" cy="193" r="4" fill="#000"/>
  <text x="302" y="188" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">P (fix)</text>

  <!-- Small cross hairs at P -->
  <line x1="285" y1="193" x2="305" y2="193" stroke="#000" stroke-width="2"/>
  <line x1="295" y1="183" x2="295" y2="203" stroke="#000" stroke-width="2"/>

  <!-- AB baseline -->
  <line x1="120" y1="340" x2="380" y2="340" stroke="#000" stroke-width="2.5"/>
  <text x="235" y="358" font-family="Georgia,serif" font-size="11" fill="#000">Known baseline AB</text>

  <!-- Info box -->
  <rect x="40" y="385" width="420" height="60" rx="5" fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="5,3"/>
  <text x="52" y="405" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Method: Take bearings to P from two known stations A, B</text>
  <text x="52" y="423" font-family="Georgia,serif" font-size="11" fill="#000">Draw bearing lines; intersection = position fix of P</text>
  <text x="52" y="439" font-family="Georgia,serif" font-size="10" fill="#000">Three bearings (triangle of error) improve accuracy</text>
</svg>`;

