  // ─── 24. BEARING DIAGRAM ANNOTATED STEP BY STEP ───────────────────────────
  static bearingDiagramAnnotatedStepByStepDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 480">

  <text x="90" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Bearing Diagram — Annotated Step by Step</text>
  <text x="60" y="38" font-family="Georgia,serif" font-size="10" fill="#444">Example: Find bearing of Q from P, given diagram information</text>

  <!-- Step panels at bottom, diagram at top -->

  <!-- Observer P at (200,300) -->
  <circle cx="200" cy="300" r="8" fill="#000"/>
  <text x="174" y="298" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">P</text>

  <!-- Target Q at (370,160) -->
  <circle cx="370" cy="160" r="8" fill="#000"/>
  <text x="376" y="158" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Q</text>

  <!-- Step 1: Draw North line at P -->
  <line x1="200" y1="340" x2="200" y2="80" stroke="#000" stroke-width="2.5" stroke-dasharray="6,4"/>
  <polygon points="194,90 200,72 206,90" fill="#000"/>
  <text x="184" y="68" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">N</text>
  <!-- Step 1 callout -->
  <line x1="200" y1="185" x2="60" y2="155" stroke="#000" stroke-width="1.5"/>
  <text x="20" y="148" font-family="Georgia,serif" font-size="10" fill="#000">① North line</text>
  <text x="20" y="160" font-family="Georgia,serif" font-size="10" fill="#000">   at P</text>

  <!-- Step 2: Draw line PQ -->
  <line x1="200" y1="300" x2="370" y2="160" stroke="#000" stroke-width="3.5"/>
  <polygon points="358,165 376,152 370,168" fill="#000"/>
  <!-- Step 2 callout -->
  <line x1="285" y1="230" x2="430" y2="215" stroke="#000" stroke-width="1.5"/>
  <text x="392" y="208" font-family="Georgia,serif" font-size="10" fill="#000">② Line PQ</text>

  <!-- Step 3: Bearing arc (clockwise from N to PQ) -->
  <!-- angle of PQ: dx=170, dy=−140, bearing=atan(170/140)≈50.5° -->
  <path d="M 200,258 A 42,42 0 0,1 232,272" fill="none" stroke="#000" stroke-width="3"/>
  <!-- Step 3 callout -->
  <line x1="218" y1="262" x2="340" y2="262" stroke="#000" stroke-width="1.5"/>
  <text x="342" y="258" font-family="Georgia,serif" font-size="10" fill="#000">③ Measure angle</text>
  <text x="342" y="270" font-family="Georgia,serif" font-size="10" fill="#000">   clockwise from N</text>

  <!-- Bearing value -->
  <text x="212" y="253" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">051°</text>

  <!-- Step 4: Write as 3 figures -->
  <!-- callout at bottom -->
  <line x1="200" y1="300" x2="100" y2="342" stroke="#000" stroke-width="1.5"/>
  <text x="30" y="338" font-family="Georgia,serif" font-size="10" fill="#000">④ Write as</text>
  <text x="30" y="350" font-family="Georgia,serif" font-size="10" fill="#000">   3 figures: 051°</text>

  <!-- Summary box -->
  <rect x="50" y="380" width="420" height="84" rx="5" fill="none" stroke="#000" stroke-width="3" stroke-dasharray="0"/>
  <text x="62" y="400" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Step-by-step summary:</text>
  <text x="62" y="418" font-family="Georgia,serif" font-size="10" fill="#000">① Draw a North line (↑) at the observer point P</text>
  <text x="62" y="434" font-family="Georgia,serif" font-size="10" fill="#000">② Draw the direction line from P to target Q</text>
  <text x="62" y="450" font-family="Georgia,serif" font-size="10" fill="#000">③ Measure angle CLOCKWISE from North to PQ with protractor</text>
  <text x="62" y="466" font-family="Georgia,serif" font-size="10" fill="#000">④ State as 3-figure bearing: bearing of Q from P = 051°</text>
</svg>`;

