  // ─── 21. QUADRATIC ROOT CHECK DIAGRAM ────────────────────────────────────
  static quadraticRootCheckDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 480">

  <!-- Title -->
  <text x="70" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Quadratic Root Check — Verify by Substitution</text>
  <text x="90" y="38" font-family="Georgia,serif" font-size="10" fill="#444">Equation:  x² − 5x + 6 = 0   Roots:  x = 2  and  x = 3</text>

  <!-- Discriminant box -->
  <rect x="40" y="50" width="440" height="64" rx="5" fill="none" stroke="#000" stroke-width="3"/>
  <text x="54" y="70" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Step 1 — Discriminant Δ = b² − 4ac</text>
  <text x="54" y="88" font-family="Georgia,serif" font-size="12" fill="#000">a=1, b=−5, c=6   →   Δ = (−5)² − 4(1)(6) = 25 − 24 = 1</text>
  <text x="54" y="106" font-family="Georgia,serif" font-size="12" fill="#000">Δ &gt; 0  →  two distinct real roots</text>

  <!-- Quadratic formula box -->
  <rect x="40" y="126" width="440" height="64" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="54" y="146" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Step 2 — Quadratic Formula</text>
  <text x="54" y="164" font-family="Georgia,serif" font-size="12" fill="#000">x = (−b ± √Δ) / 2a  =  (5 ± √1) / 2  =  (5 ± 1) / 2</text>
  <text x="54" y="182" font-family="Georgia,serif" font-size="12" fill="#000">x₁ = (5+1)/2 = 3      x₂ = (5−1)/2 = 2</text>

  <!-- Verification columns -->
  <line x1="40" y1="202" x2="470" y2="202" stroke="#000" stroke-width="2"/>

  <!-- LHS check x=3 -->
  <rect x="40" y="210" width="204" height="120" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="54" y="230" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Check x = 3:</text>
  <text x="54" y="250" font-family="Georgia,serif" font-size="12" fill="#000">LHS = (3)² − 5(3) + 6</text>
  <text x="54" y="268" font-family="Georgia,serif" font-size="12" fill="#000">    = 9 − 15 + 6</text>
  <text x="54" y="286" font-family="Georgia,serif" font-size="12" fill="#000">    = 0</text>
  <text x="54" y="320" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">LHS = RHS = 0  ✓</text>

  <!-- LHS check x=2 -->
  <rect x="256" y="210" width="204" height="120" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="270" y="230" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Check x = 2:</text>
  <text x="270" y="250" font-family="Georgia,serif" font-size="12" fill="#000">LHS = (2)² − 5(2) + 6</text>
  <text x="270" y="268" font-family="Georgia,serif" font-size="12" fill="#000">    = 4 − 10 + 6</text>
  <text x="270" y="286" font-family="Georgia,serif" font-size="12" fill="#000">    = 0</text>
  <text x="270" y="320" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">LHS = RHS = 0  ✓</text>

  <!-- Factor form -->
  <line x1="40" y1="342" x2="470" y2="342" stroke="#000" stroke-width="2"/>
  <text x="50" y="362" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Factor form (confirms roots):</text>
  <text x="50" y="382" font-family="Georgia,serif" font-size="12" fill="#000">x² − 5x + 6  =  (x − 2)(x − 3)</text>
  <text x="50" y="400" font-family="Georgia,serif" font-size="11" fill="#000">Setting each factor to zero:  x − 2 = 0  →  x = 2</text>
  <text x="50" y="418" font-family="Georgia,serif" font-size="11" fill="#000">                               x − 3 = 0  →  x = 3</text>

  <!-- Sum/product check -->
  <rect x="40" y="432" width="440" height="36" rx="5" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="6,3"/>
  <text x="54" y="450" font-family="Georgia,serif" font-size="11" fill="#000">Vieta's check:  sum of roots = −b/a = 5  ✓ (2+3=5)    product = c/a = 6  ✓ (2×3=6)</text>

  <rect x="30" y="30" width="462" height="448" rx="4" fill="none" stroke="#000" stroke-width="2"/>
</svg>`;

  // ─── 22. LHS RHS VERIFICATION DIAGRAM ────────────────────────────────────
