  // ─── 24. BIDMAS MULTI-STEP EXPRESSION DIAGRAM ─────────────────────────────
  static bidmasMultiStepExpressionDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 500">

  <!-- Title -->
  <text x="80" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">BIDMAS — Multi-Step Expression Order</text>
  <text x="60" y="38" font-family="Georgia,serif" font-size="10" fill="#444">B=Brackets  I=Indices  D=Division  M=Multiplication  A=Addition  S=Subtraction</text>

  <!-- BIDMAS order strip -->
  <rect x="40" y="50" width="60" height="30" rx="3" fill="none" stroke="#000" stroke-width="3"/>
  <text x="57" y="70" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">B</text>
  <line x1="100" y1="65" x2="118" y2="65" stroke="#000" stroke-width="2.5"/>
  <polygon points="114,61 122,65 114,69" fill="#000"/>

  <rect x="122" y="50" width="60" height="30" rx="3" fill="none" stroke="#000" stroke-width="3"/>
  <text x="139" y="70" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">I</text>
  <line x1="182" y1="65" x2="200" y2="65" stroke="#000" stroke-width="2.5"/>
  <polygon points="196,61 204,65 196,69" fill="#000"/>

  <rect x="204" y="50" width="60" height="30" rx="3" fill="none" stroke="#000" stroke-width="3"/>
  <text x="218" y="70" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">D/M</text>
  <line x1="264" y1="65" x2="282" y2="65" stroke="#000" stroke-width="2.5"/>
  <polygon points="278,61 286,65 278,69" fill="#000"/>

  <rect x="286" y="50" width="60" height="30" rx="3" fill="none" stroke="#000" stroke-width="3"/>
  <text x="298" y="70" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">A/S</text>

  <!-- Worked example -->
  <text x="50" y="108" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Expression:  3 + (2 × 4)² ÷ 8 − 1</text>

  <!-- Step by step breakdown with brackets around active part -->

  <!-- Step 1: Brackets -->
  <rect x="40" y="120" width="440" height="32" rx="3" fill="none" stroke="#000" stroke-width="1.5"/>
  <text x="52" y="137" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">① Brackets:</text>
  <text x="148" y="137" font-family="Georgia,serif" font-size="11" fill="#000">3 + </text>
  <rect x="174" y="124" width="46" height="22" rx="2" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="178" y="139" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">(2×4)</text>
  <text x="222" y="137" font-family="Georgia,serif" font-size="11" fill="#000">² ÷ 8 − 1  →  3 + 8² ÷ 8 − 1</text>

  <!-- Step 2: Indices -->
  <rect x="40" y="152" width="440" height="32" rx="3" fill="none" stroke="#000" stroke-width="1.5"/>
  <text x="52" y="169" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">② Indices:</text>
  <text x="140" y="169" font-family="Georgia,serif" font-size="11" fill="#000">3 + </text>
  <rect x="162" y="156" width="22" height="22" rx="2" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="165" y="171" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">8²</text>
  <text x="186" y="169" font-family="Georgia,serif" font-size="11" fill="#000"> ÷ 8 − 1  →  3 + 64 ÷ 8 − 1</text>

  <!-- Step 3: Division -->
  <rect x="40" y="184" width="440" height="32" rx="3" fill="none" stroke="#000" stroke-width="1.5"/>
  <text x="52" y="201" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">③ Division:</text>
  <text x="146" y="201" font-family="Georgia,serif" font-size="11" fill="#000">3 + </text>
  <rect x="172" y="188" width="50" height="22" rx="2" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="175" y="203" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">64 ÷ 8</text>
  <text x="224" y="201" font-family="Georgia,serif" font-size="11" fill="#000"> − 1  →  3 + 8 − 1</text>

  <!-- Step 4: Addition -->
  <rect x="40" y="216" width="440" height="32" rx="3" fill="none" stroke="#000" stroke-width="1.5"/>
  <text x="52" y="233" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">④ Addition:</text>
  <rect x="146" y="220" width="44" height="22" rx="2" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="150" y="235" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">3 + 8</text>
  <text x="192" y="233" font-family="Georgia,serif" font-size="11" fill="#000"> − 1  →  11 − 1</text>

  <!-- Step 5: Subtraction / Result -->
  <rect x="40" y="248" width="440" height="32" rx="3" fill="none" stroke="#000" stroke-width="3"/>
  <text x="52" y="265" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">⑤ Subtraction:</text>
  <rect x="156" y="252" width="42" height="22" rx="2" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="160" y="267" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">11 − 1</text>
  <text x="202" y="265" font-family="Georgia,serif" font-size="11" fill="#000"> = </text>
  <text x="218" y="265" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">10  ✓</text>

  <!-- Common mistakes box -->
  <line x1="40" y1="295" x2="470" y2="295" stroke="#000" stroke-width="1.5" stroke-dasharray="5,3"/>
  <text x="50" y="315" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Common errors if BIDMAS is ignored:</text>

  <!-- Wrong method 1 -->
  <text x="50" y="338" font-family="Georgia,serif" font-size="11" fill="#000">✗ Left to right only:  3+2=5, 5×4=20, 20²=400, 400÷8=50, 50−1=49  ✗</text>
  <!-- strikethrough -->
  <line x1="46" y1="334" x2="460" y2="334" stroke="#000" stroke-width="1" stroke-dasharray="4,2"/>

  <!-- Wrong method 2 -->
  <text x="50" y="360" font-family="Georgia,serif" font-size="11" fill="#000">✗ Ignoring indices before division:  3+(8÷8)=3+1=4, 4²=16, 16−1=15  ✗</text>
  <line x1="46" y1="356" x2="460" y2="356" stroke="#000" stroke-width="1" stroke-dasharray="4,2"/>

  <!-- Second worked example -->
  <line x1="40" y1="378" x2="470" y2="378" stroke="#000" stroke-width="1.5" stroke-dasharray="5,3"/>
  <text x="50" y="398" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Example 2:  12 ÷ (2 + 1) × 3² − 5</text>
  <text x="50" y="418" font-family="Georgia,serif" font-size="11" fill="#000">B: 12 ÷ (3) × 3² − 5</text>
  <text x="50" y="436" font-family="Georgia,serif" font-size="11" fill="#000">I: 12 ÷ 3 × 9 − 5</text>
  <text x="50" y="454" font-family="Georgia,serif" font-size="11" fill="#000">D&amp;M (L→R): 4 × 9 − 5 = 36 − 5 = </text>
  <text x="296" y="454" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">31</text>

  <rect x="30" y="30" width="462" height="456" rx="4" fill="none" stroke="#000" stroke-width="2"/>
</svg>`;

