  // ─── 32. INTEGRAL ARC LENGTH INFINITESIMAL DS ─────────────────────────────
  static integralArcLengthInfinitesimalDssvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 500">

  <!-- Title -->
  <text x="60" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Arc Length Integral — Infinitesimal ds Derivation</text>

  <!-- Curve (Bezier approximating y = x² style curve) -->
  <path d="M70,400 C120,380 180,300 240,240 S350,140 440,100"
        fill="none" stroke="#000" stroke-width="3.5"/>

  <!-- Axes -->
  <line x1="60" y1="430" x2="460" y2="430" stroke="#000" stroke-width="2.5"/>
  <polygon points="456,425 468,430 456,435" fill="#000"/>
  <text x="474" y="434" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">x</text>

  <line x1="60" y1="440" x2="60" y2="60" stroke="#000" stroke-width="2.5"/>
  <polygon points="55,64 60,52 65,64" fill="#000"/>
  <text x="64" y="50" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">y</text>

  <!-- A small element on the curve: dx, dy, ds triangle -->
  <!-- Point P1 ≈ (230,248), P2 ≈ (270,220) -->
  <circle cx="230" cy="248" r="5" fill="#000"/>
  <circle cx="280" cy="218" r="5" fill="#000"/>

  <!-- horizontal leg dx -->
  <line x1="230" y1="248" x2="280" y2="248" stroke="#000" stroke-width="2.5"/>
  <!-- vertical leg dy -->
  <line x1="280" y1="248" x2="280" y2="218" stroke="#000" stroke-width="2.5"/>
  <!-- hypotenuse ds (the arc element, shown slightly curved) -->
  <path d="M230,248 C246,244 264,228 280,218" fill="none" stroke="#000" stroke-width="3.5"/>

  <!-- Labels -->
  <text x="248" y="264" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">dx</text>
  <text x="284" y="238" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">dy</text>
  <text x="234" y="228" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">ds</text>

  <!-- Right angle marker -->
  <rect x="270" y="238" width="10" height="10" fill="none" stroke="#000" stroke-width="1.8"/>

  <!-- P and Q labels -->
  <text x="216" y="246" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">P</text>
  <text x="284" y="216" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Q</text>

  <!-- Full arc with endpoints labelled -->
  <text x="64" y="402" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">A</text>
  <text x="440" y="97" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">B</text>

  <!-- Total arc L label -->
  <text x="330" y="190" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">L = ∫ds</text>

  <!-- Derivation panel -->
  <rect x="30" y="330" width="460" height="160" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="46" y="352" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Derivation of ds (Pythagoras in the limit):</text>
  <line x1="30" y1="358" x2="490" y2="358" stroke="#000" stroke-width="1.5"/>
  <text x="46" y="378" font-family="Georgia,serif" font-size="12" fill="#000">ds² = dx² + dy²</text>
  <text x="46" y="398" font-family="Georgia,serif" font-size="12" fill="#000">ds  = √(dx² + dy²) = √(1 + (dy/dx)²) · dx</text>
  <text x="46" y="418" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">L = ∫ₐᵇ √(1 + (dy/dx)²) dx</text>
  <line x1="46" y1="425" x2="380" y2="425" stroke="#000" stroke-width="2"/>
  <text x="46" y="445" font-family="Georgia,serif" font-size="11" fill="#000">Parametric:  L = ∫ √((dx/dt)² + (dy/dt)²) dt</text>
  <text x="46" y="462" font-family="Georgia,serif" font-size="11" fill="#000">Polar:        L = ∫ √(r² + (dr/dθ)²) dθ</text>
  <text x="46" y="479" font-family="Georgia,serif" font-size="11" fill="#000">All forms follow from the same infinitesimal right-triangle argument.</text>

  <rect x="20" y="28" width="476" height="462" rx="4" fill="none" stroke="#000" stroke-width="2"/>
</svg>`;


