  // ─── 24. SAME BASE SOLVING ────────────────────────────────────────────────
  static sameBaseSolvingDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 400">

  <text x="80" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Solving Exponential Equations — Same Base Method</text>
  <text x="100" y="38" font-family="Georgia,serif" font-size="10" fill="#444">If aᵐ = aⁿ and a &gt; 0, a ≠ 1, then m = n</text>

  <!-- Example equation -->
  <text x="100" y="80" font-family="Georgia,serif" font-size="18" font-weight="bold" fill="#000">Solve:  4^(x+1) = 8^(x−2)</text>

  <!-- Step 1 -->
  <rect x="30" y="104" width="30" height="30" rx="3" fill="#000"/>
  <text x="38" y="124" font-family="Georgia,serif" font-size="14" fill="#fff">1</text>
  <text x="70" y="124" font-family="Georgia,serif" font-size="13" fill="#000">Write both sides as powers of 2:</text>
  <text x="70" y="148" font-family="Georgia,serif" font-size="15" font-weight="bold" fill="#000">4 = 2²    and    8 = 2³</text>

  <!-- Step 2 -->
  <rect x="30" y="168" width="30" height="30" rx="3" fill="#000"/>
  <text x="38" y="188" font-family="Georgia,serif" font-size="14" fill="#fff">2</text>
  <text x="70" y="188" font-family="Georgia,serif" font-size="13" fill="#000">Rewrite equation:</text>
  <text x="70" y="212" font-family="Georgia,serif" font-size="15" font-weight="bold" fill="#000">(2²)^(x+1) = (2³)^(x−2)</text>

  <!-- Step 3 -->
  <rect x="30" y="230" width="30" height="30" rx="3" fill="#000"/>
  <text x="38" y="250" font-family="Georgia,serif" font-size="14" fill="#fff">3</text>
  <text x="70" y="250" font-family="Georgia,serif" font-size="13" fill="#000">Apply power of power law:</text>
  <text x="70" y="274" font-family="Georgia,serif" font-size="15" font-weight="bold" fill="#000">2^(2x+2) = 2^(3x−6)</text>

  <!-- Step 4: equate exponents -->
  <rect x="30" y="292" width="30" height="30" rx="3" fill="#000"/>
  <text x="38" y="312" font-family="Georgia,serif" font-size="14" fill="#fff">4</text>
  <text x="70" y="312" font-family="Georgia,serif" font-size="13" fill="#000">Same base → equate exponents:</text>
  <text x="70" y="336" font-family="Georgia,serif" font-size="15" font-weight="bold" fill="#000">2x + 2 = 3x − 6</text>

  <!-- Step 5: solve -->
  <rect x="30" y="354" width="30" height="30" rx="3" fill="#000"/>
  <text x="38" y="374" font-family="Georgia,serif" font-size="14" fill="#fff">5</text>
  <text x="70" y="374" font-family="Georgia,serif" font-size="13" fill="#000">Solve linear equation:</text>
  <text x="70" y="394" font-family="Georgia,serif" font-size="15" font-weight="bold" fill="#000">x = 8  ✓</text>

  <!-- Arrow connecting equating step -->
  <path d="M400,274 C450,274 450,316 400,316" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="5,3"/>
  <polygon points="404,312 396,320 404,324" fill="#000"/>
  <text x="454" y="297" font-family="Georgia,serif" font-size="11" fill="#000">bases</text>
  <text x="454" y="311" font-family="Georgia,serif" font-size="11" fill="#000">equal</text>
</svg>`;

