  // ─── 28. COMMON ALGEBRA ERRORS DIAGRAM ────────────────────────────────────
  // Red-cross / green-tick comparison of wrong vs right
  static commonAlgebraErrorsDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 560 520">

  <!-- Title -->
  <text x="100" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Common Algebra Errors — Wrong vs Correct</text>

  <!-- Header row -->
  <rect x="10" y="35" width="270" height="28" rx="3" fill="none" stroke="#000" stroke-width="2.5"/>
  <rect x="290" y="35" width="260" height="28" rx="3" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="85" y="54" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">✗ WRONG</text>
  <text x="355" y="54" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">✓ CORRECT</text>

  <!-- Row dividers -->
  <line x1="10" y1="63" x2="550" y2="63" stroke="#000" stroke-width="1.5"/>

  <!-- Error 1: (a+b)² -->
  <rect x="10" y="68" width="540" height="56" rx="2" fill="none" stroke="#000" stroke-width="1.5" stroke-dasharray="3,3"/>
  <text x="18" y="86" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">Error 1: Squaring a binomial</text>
  <text x="18" y="106" font-family="Georgia,serif" font-size="14" fill="#000">(x+3)² = x²+9</text>
  <!-- Large cross -->
  <line x1="168" y1="74" x2="182" y2="118" stroke="#000" stroke-width="3"/>
  <line x1="182" y1="74" x2="168" y2="118" stroke="#000" stroke-width="3"/>
  <text x="298" y="86" font-family="Georgia,serif" font-size="10" fill="#000">Must use FOIL/identity:</text>
  <text x="298" y="106" font-family="Georgia,serif" font-size="14" fill="#000">(x+3)² = x²+6x+9</text>

  <!-- Error 2: Cancelling terms -->
  <rect x="10" y="132" width="540" height="56" rx="2" fill="none" stroke="#000" stroke-width="1.5" stroke-dasharray="3,3"/>
  <text x="18" y="150" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">Error 2: Cancelling terms (not factors)</text>
  <text x="18" y="170" font-family="Georgia,serif" font-size="14" fill="#000">(x+5)/(x+3) = 5/3</text>
  <line x1="174" y1="138" x2="188" y2="182" stroke="#000" stroke-width="3"/>
  <line x1="188" y1="138" x2="174" y2="182" stroke="#000" stroke-width="3"/>
  <text x="298" y="150" font-family="Georgia,serif" font-size="10" fill="#000">x is a term, not a factor here:</text>
  <text x="298" y="170" font-family="Georgia,serif" font-size="14" fill="#000">(x+5)/(x+3) cannot cancel</text>

  <!-- Error 3: Negative indices -->
  <rect x="10" y="196" width="540" height="56" rx="2" fill="none" stroke="#000" stroke-width="1.5" stroke-dasharray="3,3"/>
  <text x="18" y="214" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">Error 3: Negative indices</text>
  <text x="18" y="234" font-family="Georgia,serif" font-size="14" fill="#000">x⁻² = −x²</text>
  <line x1="90" y1="202" x2="104" y2="246" stroke="#000" stroke-width="3"/>
  <line x1="104" y1="202" x2="90" y2="246" stroke="#000" stroke-width="3"/>
  <text x="298" y="214" font-family="Georgia,serif" font-size="10" fill="#000">Negative index = reciprocal:</text>
  <text x="298" y="234" font-family="Georgia,serif" font-size="14" fill="#000">x⁻² = 1/x²</text>

  <!-- Error 4: Distributing power -->
  <rect x="10" y="260" width="540" height="56" rx="2" fill="none" stroke="#000" stroke-width="1.5" stroke-dasharray="3,3"/>
  <text x="18" y="278" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">Error 4: Power of a sum</text>
  <text x="18" y="298" font-family="Georgia,serif" font-size="14" fill="#000">√(x²+9) = x+3</text>
  <line x1="145" y1="266" x2="159" y2="310" stroke="#000" stroke-width="3"/>
  <line x1="159" y1="266" x2="145" y2="310" stroke="#000" stroke-width="3"/>
  <text x="298" y="278" font-family="Georgia,serif" font-size="10" fill="#000">√ does NOT distribute over addition:</text>
  <text x="298" y="298" font-family="Georgia,serif" font-size="14" fill="#000">√(x²+9) ≠ x+3, leave as is</text>

  <!-- Error 5: Multiplying indices, different bases -->
  <rect x="10" y="324" width="540" height="56" rx="2" fill="none" stroke="#000" stroke-width="1.5" stroke-dasharray="3,3"/>
  <text x="18" y="342" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">Error 5: Adding exponents (different bases)</text>
  <text x="18" y="362" font-family="Georgia,serif" font-size="14" fill="#000">x³ × y⁵ = (xy)⁸</text>
  <line x1="140" y1="330" x2="154" y2="374" stroke="#000" stroke-width="3"/>
  <line x1="154" y1="330" x2="140" y2="374" stroke="#000" stroke-width="3"/>
  <text x="298" y="342" font-family="Georgia,serif" font-size="10" fill="#000">Only add exponents for SAME base:</text>
  <text x="298" y="362" font-family="Georgia,serif" font-size="14" fill="#000">x³ × y⁵ stays as x³y⁵</text>

  <!-- Error 6: Division of surds -->
  <rect x="10" y="388" width="540" height="56" rx="2" fill="none" stroke="#000" stroke-width="1.5" stroke-dasharray="3,3"/>
  <text x="18" y="406" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">Error 6: Surd in denominator left unsimplified</text>
  <text x="18" y="426" font-family="Georgia,serif" font-size="14" fill="#000">1/√2  (left as is)</text>
  <line x1="120" y1="394" x2="134" y2="438" stroke="#000" stroke-width="3"/>
  <line x1="134" y1="394" x2="120" y2="438" stroke="#000" stroke-width="3"/>
  <text x="298" y="406" font-family="Georgia,serif" font-size="10" fill="#000">Rationalise the denominator:</text>
  <text x="298" y="426" font-family="Georgia,serif" font-size="14" fill="#000">1/√2 = √2/2</text>

  <!-- Error 7: Zero power -->
  <rect x="10" y="452" width="540" height="56" rx="2" fill="none" stroke="#000" stroke-width="1.5" stroke-dasharray="3,3"/>
  <text x="18" y="470" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">Error 7: Zero power</text>
  <text x="18" y="490" font-family="Georgia,serif" font-size="14" fill="#000">5x⁰ = 1</text>
  <line x1="62" y1="458" x2="76" y2="502" stroke="#000" stroke-width="3"/>
  <line x1="76" y1="458" x2="62" y2="502" stroke="#000" stroke-width="3"/>
  <text x="298" y="470" font-family="Georgia,serif" font-size="10" fill="#000">x⁰=1 but the 5 remains:</text>
  <text x="298" y="490" font-family="Georgia,serif" font-size="14" fill="#000">5x⁰ = 5×1 = 5</text>
</svg>`;


