// ─── 10. LINE INCLINATION ANGLE DIAGRAM ───────────────────────────────────
static lineInclinationAngleDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 420">

  <text x="80" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Line Inclination and Gradient (Slope)</text>

  <!-- Axes -->
  <line x1="40" y1="300" x2="480" y2="300" stroke="#000" stroke-width="2.5"/>
  <polygon points="476,295 488,300 476,305" fill="#000"/>
  <text x="492" y="304" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">x</text>
  <line x1="80" y1="380" x2="80" y2="40" stroke="#000" stroke-width="2.5"/>
  <polygon points="75,44 80,32 85,44" fill="#000"/>
  <text x="84" y="30" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">y</text>

  <!-- Main inclined line: from (80,300) to (440,100) -->
  <line x1="80" y1="300" x2="440" y2="100" stroke="#000" stroke-width="4"/>

  <!-- Horizontal reference through starting point -->
  <line x1="80" y1="300" x2="440" y2="300" stroke="#000" stroke-width="1.5" stroke-dasharray="7,4"/>

  <!-- Inclination angle arc at (80,300) -->
  <path d="M 160,300 A 80,80 0 0,0 116,256" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="168" y="292" font-family="Georgia,serif" font-size="14" font-weight="bold" font-style="italic" fill="#000">α</text>
  <text x="170" y="278" font-family="Georgia,serif" font-size="10" fill="#000">inclination</text>

  <!-- Rise and Run (right triangle) -->
  <!-- From point (280,300) up to (280,200), then to (440,200) — wait, let's use specific points on line -->
  <!-- Points on line: at x=200→y=300+(100-300)/(440-80)*(200-80)=300-200*(120/360) ≈ 300-66.7=233 
       so (200,233), at x=380→300-200*(300/360)≈300-166.7=133 so (380,133) -->
  <line x1="200" y1="233" x2="380" y2="233" stroke="#000" stroke-width="2" stroke-dasharray="5,3"/>
  <line x1="380" y1="233" x2="380" y2="133" stroke="#000" stroke-width="2" stroke-dasharray="5,3"/>
  <!-- Right angle box -->
  <rect x="366" y="219" width="14" height="14" fill="none" stroke="#000" stroke-width="2"/>
  <!-- Rise label -->
  <text x="388" y="190" font-family="Georgia,serif" font-size="13" font-weight="bold" font-style="italic" fill="#000">rise</text>
  <!-- Run label -->
  <text x="272" y="248" font-family="Georgia,serif" font-size="13" font-weight="bold" font-style="italic" fill="#000">run</text>

  <!-- Endpoint dots -->
  <circle cx="80" cy="300" r="5" fill="#000"/>
  <circle cx="440" cy="100" r="5" fill="#000"/>
  <text x="50" y="316" font-family="Georgia,serif" font-size="10" fill="#000">(x₁,y₁)</text>
  <text x="444" y="98" font-family="Georgia,serif" font-size="10" fill="#000">(x₂,y₂)</text>

  <!-- Formula box -->
  <rect x="40" y="330" width="460" height="78" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="50" y="348" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Gradient (slope):  m = rise/run = (y₂−y₁)/(x₂−x₁) = tan α</text>
  <text x="50" y="366" font-family="Georgia,serif" font-size="11" fill="#000">Inclination α: angle measured CCW from positive x-axis to line</text>
  <text x="50" y="384" font-family="Georgia,serif" font-size="11" fill="#000">α ∈ [0°, 180°)  |  m > 0 → acute α  |  m &lt; 0 → obtuse α</text>
  <text x="50" y="400" font-family="Georgia,serif" font-size="11" fill="#000">Horizontal: m=0, α=0°  |  Vertical: m undefined, α=90°</text>
</svg>`;

// ─── 11. ANGLE BETWEEN TWO LINES GRADIENT DIAGRAM ─────────────────────────
static angleBetweenTwoLinesGradientDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 440">

  <text x="80" y="22" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">Angle Between Two Lines — Gradient Method</text>

  <!-- Axes -->
  <line x1="40" y1="280" x2="480" y2="280" stroke="#000" stroke-width="2.5"/>
  <polygon points="476,275 488,280 476,285" fill="#000"/>
  <text x="492" y="284" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">x</text>
  <line x1="250" y1="420" x2="250" y2="50" stroke="#000" stroke-width="2.5"/>
  <polygon points="245,54 250,42 255,54" fill="#000"/>
  <text x="254" y="40" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">y</text>

  <!-- Line L1: steep positive slope, from (80,400) to (380,100) -->
  <line x1="80" y1="400" x2="380" y2="100" stroke="#000" stroke-width="3.5"/>
  <text x="386" y="97" font-family="Georgia,serif" font-size="12" font-weight="bold" font-style="italic" fill="#000">L₁ (m₁)</text>

  <!-- Line L2: shallow positive slope, from (60,320) to (460,220) -->
  <line x1="60" y1="320" x2="460" y2="220" stroke="#000" stroke-width="3.5" stroke-dasharray="10,4"/>
  <text x="462" y="218" font-family="Georgia,serif" font-size="12" font-weight="bold" font-style="italic" fill="#000">L₂ (m₂)</text>

  <!-- Intersection point: solve (80,400)+t(300,-300) with (60,320)+s(400,-100)
       80+300t = 60+400s, 400-300t = 320-100s → approx (212, 268) -->
  <circle cx="212" cy="268" r="6" fill="#000"/>

  <!-- Inclination arcs from x-axis -->
  <!-- α₁ (L1 inclination, steeper) -->
  <path d="M 260,280 A 48,48 0 0,0 240,244" fill="none" stroke="#000" stroke-width="2"/>
  <text x="268" y="270" font-family="Georgia,serif" font-size="11" font-style="italic" fill="#000">α₁</text>

  <!-- α₂ (L2 inclination, shallower) -->
  <path d="M 280,280 A 68,68 0 0,0 270,258" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="4,3"/>
  <text x="290" y="270" font-family="Georgia,serif" font-size="11" font-style="italic" fill="#000">α₂</text>

  <!-- Angle θ between lines at intersection -->
  <path d="M 226,253 A 22,22 0 0,0 218,270" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="198" y="252" font-family="Georgia,serif" font-size="13" font-weight="bold" font-style="italic" fill="#000">θ</text>

  <!-- Formula box -->
  <rect x="40" y="370" width="440" height="60" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="50" y="388" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Angle between two lines:</text>
  <text x="50" y="406" font-family="Georgia,serif" font-size="12" fill="#000">tan θ = |(m₁ − m₂) / (1 + m₁m₂)|</text>
  <text x="50" y="422" font-family="Georgia,serif" font-size="10" fill="#000">θ = acute angle between lines  |  Lines ⊥ when m₁m₂ = −1  |  Parallel when m₁ = m₂</text>

  <!-- Horizontal reference through intersection -->
  <line x1="130" y1="268" x2="340" y2="268" stroke="#000" stroke-width="1.2" stroke-dasharray="4,3"/>
</svg>`;

