// ─── 14. UNIT CIRCLE COORDINATE REPRESENTATION ────────────────────────────
static unitCircleCoordinateRepresentationsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 500 500">

  <text x="80" y="22" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">Unit Circle — Coordinate Representation</text>

  <!-- Axes -->
  <line x1="60" y1="260" x2="440" y2="260" stroke="#000" stroke-width="2.5"/>
  <polygon points="436,255 448,260 436,265" fill="#000"/>
  <text x="452" y="264" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">x</text>
  <line x1="250" y1="440" x2="250" y2="80" stroke="#000" stroke-width="2.5"/>
  <polygon points="245,84 250,72 255,84" fill="#000"/>
  <text x="254" y="70" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">y</text>

  <!-- Unit circle -->
  <circle cx="250" cy="260" r="160" fill="none" stroke="#000" stroke-width="3"/>

  <!-- Point P at angle θ (let's use 40°): cos40≈0.766, sin40≈0.643
       x=250+160*0.766=373, y=260-160*0.643=157 -->
  <circle cx="373" cy="157" r="6" fill="#000"/>

  <!-- Radius -->
  <line x1="250" y1="260" x2="373" y2="157" stroke="#000" stroke-width="3"/>
  <text x="290" y="200" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">r = 1</text>

  <!-- x-projection (horizontal leg) -->
  <line x1="250" y1="260" x2="373" y2="260" stroke="#000" stroke-width="2.5"/>
  <text x="294" y="278" font-family="Georgia,serif" font-size="11" font-style="italic" fill="#000">x = cosθ</text>

  <!-- y-projection (vertical leg) -->
  <line x1="373" y1="260" x2="373" y2="157" stroke="#000" stroke-width="2.5" stroke-dasharray="5,3"/>
  <text x="378" y="214" font-family="Georgia,serif" font-size="11" font-style="italic" fill="#000">y = sinθ</text>

  <!-- Right angle box -->
  <rect x="359" y="246" width="14" height="14" fill="none" stroke="#000" stroke-width="2"/>

  <!-- Angle arc -->
  <path d="M 290,260 A 40,40 0 0,0 280,228" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="296" y="246" font-family="Georgia,serif" font-size="12" font-style="italic" fill="#000">θ</text>

  <!-- Dashed projection lines to axes -->
  <line x1="373" y1="157" x2="373" y2="260" stroke="#000" stroke-width="1" stroke-dasharray="3,4"/>
  <line x1="373" y1="157" x2="250" y2="157" stroke="#000" stroke-width="1" stroke-dasharray="3,4"/>
  <!-- Tick on x axis at projection -->
  <line x1="373" y1="256" x2="373" y2="264" stroke="#000" stroke-width="2"/>
  <text x="366" y="276" font-family="Georgia,serif" font-size="9" fill="#000">cosθ</text>
  <!-- Tick on y axis at projection -->
  <line x1="246" y1="157" x2="254" y2="157" stroke="#000" stroke-width="2"/>
  <text x="256" y="161" font-family="Georgia,serif" font-size="9" fill="#000">sinθ</text>

  <!-- P label -->
  <text x="378" y="154" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">P(cosθ, sinθ)</text>

  <!-- Key facts table -->
  <rect x="40" y="400" width="420" height="88" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="50" y="418" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Key Coordinates on Unit Circle:</text>
  <text x="50" y="434" font-family="Georgia,serif" font-size="10" fill="#000">0°→(1,0)  30°→(√3/2,½)  45°→(√2/2,√2/2)  60°→(½,√3/2)</text>
  <text x="50" y="450" font-family="Georgia,serif" font-size="10" fill="#000">90°→(0,1)  180°→(−1,0)  270°→(0,−1)  360°→(1,0)</text>
  <text x="50" y="466" font-family="Georgia,serif" font-size="11" fill="#000">sinθ = y-coordinate  |  cosθ = x-coordinate  |  tanθ = y/x</text>
  <text x="50" y="480" font-family="Georgia,serif" font-size="10" fill="#000">sin²θ + cos²θ = 1 (from Pythagoras applied to any point on circle)</text>

  <text x="254" y="274" font-family="Georgia,serif" font-size="10" fill="#000">O</text>
</svg>`;

