// ─── 22. CONGRUENCE CONDITIONS SSS SAS ASA AAS RHS ────────────────────────
static congruenceConditionsSSS_SAS_ASA_AAS_RHSsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 560 560">

  <text x="100" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Triangle Congruence Conditions</text>

  <!-- ══ SSS ══ -->
  <text x="40" y="52" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">SSS (Side-Side-Side)</text>
  <polygon points="40,110 150,60 200,110" fill="none" stroke="#000" stroke-width="3.5" stroke-linejoin="round"/>
  <!-- triple ticks on all 3 sides (both triangles) -->
  <line x1="88" y1="83" x2="96" y2="91" stroke="#000" stroke-width="2.5"/>
  <line x1="92" y1="79" x2="100" y2="87" stroke="#000" stroke-width="2.5"/>
  <line x1="175" y1="83" x2="183" y2="91" stroke="#000" stroke-width="2.5"/>
  <line x1="179" y1="79" x2="187" y2="87" stroke="#000" stroke-width="2.5"/>
  <line x1="116" y1="105" x2="124" y2="113" stroke="#000" stroke-width="2.5"/>
  <text x="110" y="128" font-family="Georgia,serif" font-size="10" fill="#000">3 sides equal → ≅</text>

  <!-- ══ SAS ══ -->
  <text x="230" y="52" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">SAS (Side-Angle-Side)</text>
  <polygon points="230,110 340,60 390,110" fill="none" stroke="#000" stroke-width="3.5" stroke-linejoin="round"/>
  <line x1="278" y1="83" x2="286" y2="91" stroke="#000" stroke-width="2.5"/>
  <line x1="282" y1="79" x2="290" y2="87" stroke="#000" stroke-width="2.5"/>
  <line x1="365" y1="83" x2="373" y2="91" stroke="#000" stroke-width="2.5"/>
  <line x1="369" y1="79" x2="377" y2="87" stroke="#000" stroke-width="2.5"/>
  <path d="M 252,110 A 22,22 0 0,0 242,90" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="300" y="128" font-family="Georgia,serif" font-size="10" fill="#000">2 sides + included angle → ≅</text>

  <!-- ══ ASA ══ -->
  <text x="40" y="178" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">ASA (Angle-Side-Angle)</text>
  <polygon points="40,240 150,190 200,240" fill="none" stroke="#000" stroke-width="3.5" stroke-linejoin="round"/>
  <path d="M 62,240 A 22,22 0 0,0 54,220" fill="none" stroke="#000" stroke-width="2.5"/>
  <path d="M 176,240 A 22,22 0 0,1 186,220" fill="none" stroke="#000" stroke-width="2.5"/>
  <line x1="116" y1="215" x2="124" y2="225" stroke="#000" stroke-width="2.5"/>
  <text x="90" y="258" font-family="Georgia,serif" font-size="10" fill="#000">2 angles + included side → ≅</text>

  <!-- ══ AAS ══ -->
  <text x="230" y="178" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">AAS (Angle-Angle-Side)</text>
  <polygon points="230,240 340,190 390,240" fill="none" stroke="#000" stroke-width="3.5" stroke-linejoin="round"/>
  <path d="M 252,240 A 22,22 0 0,0 244,220" fill="none" stroke="#000" stroke-width="2.5"/>
  <path d="M 322,206 A 20,20 0 0,1 338,205" fill="none" stroke="#000" stroke-width="2.5"/>
  <line x1="366" y1="215" x2="374" y2="225" stroke="#000" stroke-width="2.5"/>
  <line x1="370" y1="219" x2="378" y2="229" stroke="#000" stroke-width="2.5"/>
  <text x="275" y="258" font-family="Georgia,serif" font-size="10" fill="#000">2 angles + non-included side → ≅</text>

  <!-- ══ RHS ══ -->
  <text x="40" y="300" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">RHS (Right-Hypotenuse-Side)</text>
  <!-- Right triangle -->
  <polygon points="40,390 40,310 180,390" fill="none" stroke="#000" stroke-width="3.5" stroke-linejoin="round"/>
  <rect x="40" y="370" width="20" height="20" fill="none" stroke="#000" stroke-width="2.5"/>
  <!-- Hyp double tick -->
  <line x1="102" y1="342" x2="110" y2="352" stroke="#000" stroke-width="2.5"/>
  <line x1="106" y1="338" x2="114" y2="348" stroke="#000" stroke-width="2.5"/>
  <!-- Leg single tick -->
  <line x1="106" y1="384" x2="114" y2="396" stroke="#000" stroke-width="2.5"/>
  <text x="40" y="410" font-family="Georgia,serif" font-size="10" fill="#000">Right angle + hyp + one side → ≅</text>

  <!-- Congruence symbol explanation -->
  <rect x="230" y="300" width="300" height="100" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="240" y="320" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Congruence (≅):</text>
  <text x="240" y="338" font-family="Georgia,serif" font-size="11" fill="#000">Triangles are congruent if they</text>
  <text x="240" y="354" font-family="Georgia,serif" font-size="11" fill="#000">have identical shape AND size.</text>
  <text x="240" y="372" font-family="Georgia,serif" font-size="11" fill="#000">All corresponding sides and angles</text>
  <text x="240" y="388" font-family="Georgia,serif" font-size="11" fill="#000">are equal.</text>

  <!-- NOT a valid condition: SSA -->
  <rect x="40" y="430" width="480" height="34" rx="4" fill="none" stroke="#000" stroke-width="2"/>
  <text x="50" y="448" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Note:</text>
  <text x="86" y="448" font-family="Georgia,serif" font-size="11" fill="#000">SSA (side-side-angle) is NOT a valid congruence condition (ambiguous case)</text>
  <text x="50" y="460" font-family="Georgia,serif" font-size="10" fill="#000">AAA proves similarity only, not congruence (angles alone don't fix size)</text>
</svg>`;

