  // Shows a common mistake: assuming vectors are parallel when they are not
  static parallelErrorCounterExampleDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 500 400">

  <!-- Title -->
  <text x="60" y="24" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Parallel Vector — Common Errors &amp; Counter-Examples</text>

  <!-- Error 1: Equal components doesn't mean parallel if signs differ inconsistently -->
  <rect x="40" y="48" width="420" height="70" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="52" y="70" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">❌ Error 1: Assuming same x-component → parallel</text>
  <text x="52" y="92" font-family="Georgia,serif" font-size="12" fill="#000">a=(3, 4) and b=(3, 7) — same x-comp but NOT parallel</text>
  <text x="52" y="110" font-family="Georgia,serif" font-size="11" fill="#000">4/7 ≠ 3/3  →  ratios differ  →  NOT parallel  ✗</text>

  <!-- Error 2: Opposite magnitudes don't need to be parallel -->
  <rect x="40" y="132" width="420" height="70" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="52" y="154" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">❌ Error 2: |a|=|b| does NOT mean a ∥ b</text>
  <text x="52" y="176" font-family="Georgia,serif" font-size="12" fill="#000">a=(3, 4)  |a|=5  and  c=(5, 0)  |c|=5</text>
  <text x="52" y="194" font-family="Georgia,serif" font-size="11" fill="#000">Same magnitude but different directions — NOT parallel  ✗</text>

  <!-- Visual counter-example -->
  <!-- Axes -->
  <line x1="60" y1="320" x2="360" y2="320" stroke="#000" stroke-width="2"/>
  <polygon points="356,315 368,320 356,325" fill="#000"/>
  <line x1="80" y1="360" x2="80" y2="240" stroke="#000" stroke-width="2"/>
  <polygon points="75,244 80,232 85,244" fill="#000"/>

  <!-- a=(3,4) scaled 30px/unit → (90,120) → tip=(170,200) -->
  <line x1="80" y1="320" x2="170" y2="200" stroke="#000" stroke-width="5"/>
  <polygon points="163,207 173,197 177,209" fill="#000"/>
  <text x="178" y="195" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">a=(3,4)</text>

  <!-- b=(3,7) → (90,210) → tip=(170,110)—out of range; use scale 20px: (60,140)→(140,180) -->
  <line x1="80" y1="320" x2="140" y2="180" stroke="#000" stroke-width="5" stroke-dasharray="7,4"/>
  <polygon points="133,187 143,177 147,189" fill="#000"/>
  <text x="146" y="173" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">b=(3,7)</text>

  <!-- c=(5,0) → (150,0) → tip=(230,320) -->
  <line x1="80" y1="320" x2="230" y2="320" stroke="#000" stroke-width="5" stroke-dasharray="5,5"/>
  <polygon points="222,313 236,320 222,327" fill="#000"/>
  <text x="238" y="316" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">c=(5,0)</text>

  <!-- Angle markers showing non-parallel -->
  <path d="M110,320 A30,30 0 0,0 104,294" fill="none" stroke="#000" stroke-width="2"/>
  <text x="114" y="308" font-family="Georgia,serif" font-size="10" fill="#000">θ₁</text>
  <path d="M104,320 A24,24 0 0,0 99,298" fill="none" stroke="#000" stroke-width="2"/>
  <text x="84" y="308" font-family="Georgia,serif" font-size="10" fill="#000">θ₂</text>
  <text x="82" y="334" font-family="Georgia,serif" font-size="10" fill="#000">θ₃=0</text>

  <!-- Legend -->
  <text x="258" y="270" font-family="Georgia,serif" font-size="11" fill="#000">θ₁ ≠ θ₂ ≠ θ₃ → none parallel</text>

  <!-- Correct test reminder -->
  <rect x="60" y="356" width="380" height="36" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="70" y="374" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Correct test ONLY: a = k·b for scalar k  or  a₁b₂ = a₂b₁</text>
</svg>`;

