  <!-- R(30°)·x̂ = (cos30,sin30) = (0.866,0.5) → (327.9,335) -->
  <line x1="250" y1="380" x2="328" y2="335" stroke="#000" stroke-width="3" stroke-dasharray="6,3"/>
