  // ─── 16. VERTICAL / HORIZONTAL DILATION OF FUNCTION GRAPH ─────────────────
  static verticalHorizontalDilationFunctionGraphsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 500 500">

  <text x="70" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Vertical and Horizontal Dilation of f(x) = x²</text>
  <text x="60" y="38" font-family="Georgia,serif" font-size="10" fill="#444">Vertical: y = a·f(x)   Horizontal: y = f(bx)   compared to original</text>

  <!-- Axes -->
  <line x1="40" y1="280" x2="460" y2="280" stroke="#000" stroke-width="2"/>
  <polygon points="456,275 468,280 456,285" fill="#000"/>
  <text x="472" y="284" font-family="Georgia,serif" font-size="12" fill="#000">x</text>
  <line x1="250" y1="460" x2="250" y2="30" stroke="#000" stroke-width="2"/>
  <polygon points="245,34 250,22 255,34" fill="#000"/>
  <text x="254" y="24" font-family="Georgia,serif" font-size="12" fill="#000">y</text>

  <!-- Tick marks (scale: 80px = 1 unit) -->
  <line x1="330" y1="276" x2="330" y2="284" stroke="#000" stroke-width="2"/>
  <text x="326" y="295" font-family="Georgia,serif" font-size="10" fill="#000">1</text>
  <line x1="170" y1="276" x2="170" y2="284" stroke="#000" stroke-width="2"/>
  <text x="162" y="295" font-family="Georgia,serif" font-size="10" fill="#000">−1</text>
  <line x1="246" y1="200" x2="254" y2="200" stroke="#000" stroke-width="2"/>
  <text x="256" y="204" font-family="Georgia,serif" font-size="10" fill="#000">1</text>
  <line x1="246" y1="120" x2="254" y2="120" stroke="#000" stroke-width="2"/>
  <text x="256" y="124" font-family="Georgia,serif" font-size="10" fill="#000">2</text>

  <!-- f(x)=x² (scale: x in units, y=x² units; 80px/unit)
       Points: x=−2:y=4→(90,−320+280=too low), use smaller: x in [−1.5,1.5]
       x=0:(250,280), x=±1:(330,200),(170,200), x=±1.5:(370,100),(130,100)
  -->
  <polyline points="112,168 130,200 170,248 210,272 250,280 290,272 330,248 370,200 388,168"
            fill="none" stroke="#000" stroke-width="3"/>
  <text x="390" y="166" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">f(x)=x²</text>

  <!-- 2·f(x)=2x²: y doubled → y=2x²; x=±1:(330,120),(170,120); x=±1.2:(346,60),(154,60) -->
  <polyline points="178,90 190,107 210,131 230,162 250,280 270,162 290,131 310,107 322,90"
            fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="8,4"/>
  <text x="318" y="86" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">2f(x)</text>
  <text x="286" y="78" font-family="Georgia,serif" font-size="9" fill="#000">(vertical stretch ×2)</text>

  <!-- f(2x)=(2x)²=4x²: x=±0.75→y=2.25→(310,100),(190,100); narrower
       Points: x=0:(250,280),x=±0.5:(290,264),(210,264),x=±0.75:(310,236),(190,236),x=±1:(330,152),(170,152)
       y=4x²*80: x=1→y=4→320px up from 280=(-40px)→y_px=280-4*80=-40 too high
       Use 80px/unit: x=0.5: y=0.25→280-20=260; x=1: y=4→280-320=-40 (off screen)
       Use x range ±0.85: x=0.85: y=4*0.72=2.89→280-231=49
  -->
  <polyline points="182,48 194,88 210,152 230,224 250,280 270,224 290,152 306,88 318,48"
            fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="4,3"/>
  <text x="320" y="44" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">f(2x)</text>
  <text x="284" y="36" font-family="Georgia,serif" font-size="9" fill="#000">(horiz. compress ×½)</text>

  <!-- ½·f(x)=½x²: y halved; x=±1→y=0.5→280-40=240; x=±1.5→y=1.125→280-90=190 -->
  <polyline points="112,235 130,247 170,264 210,276 250,280 290,276 330,264 370,247 388,235"
            fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="6,2"/>
  <text x="388" y="240" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">½f(x)</text>
  <text x="356" y="252" font-family="Georgia,serif" font-size="9" fill="#000">(vert. compress ×½)</text>

  <!-- Legend box -->
  <rect x="30" y="380" width="430" height="100" rx="5" fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="5,3"/>
  <text x="40" y="399" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Dilation rules for graphs:</text>
  <line x1="40" y1="405" x2="460" y2="405" stroke="#000" stroke-width="1"/>
  <text x="40" y="420" font-family="Georgia,serif" font-size="11" fill="#000">y = a·f(x)  →  vertical stretch/compress by |a|   (y-coords ×a)</text>
  <text x="40" y="437" font-family="Georgia,serif" font-size="11" fill="#000">y = f(bx)  →  horizontal compress/stretch by 1/|b|  (x-coords ÷b)</text>
  <text x="40" y="454" font-family="Georgia,serif" font-size="11" fill="#000">a &gt; 1 → taller  |  0&lt;a&lt;1 → flatter  |  b &gt; 1 → narrower</text>
  <text x="40" y="472" font-family="Georgia,serif" font-size="10" fill="#555">Solid=f(x) · Long-dash=2f(x) · Short-dash=f(2x) · Dot-dash=½f(x)</text>
</svg>`;

