  // ─── 18. SPIRAL SIMILARITY ────────────────────────────────────────────────
  static spiralSimilarityDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 500 500">

  <text x="110" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Spiral Similarity</text>
  <text x="60" y="38" font-family="Georgia,serif" font-size="10" fill="#444">Dilation ∘ Rotation about same centre = spiral similarity (rotation + scaling)</text>

  <!-- Axes -->
  <line x1="40" y1="280" x2="460" y2="280" stroke="#000" stroke-width="1.5"/>
  <polygon points="456,275 468,280 456,285" fill="#000"/>
  <line x1="250" y1="460" x2="250" y2="40" stroke="#000" stroke-width="1.5"/>
  <polygon points="245,44 250,32 255,44" fill="#000"/>

  <!-- Centre S=(250,280) -->
  <circle cx="250" cy="280" r="6" fill="#000"/>
  <text x="256" y="276" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">S</text>

  <!-- Original triangle T1: A=(330,220), B=(390,280), C=(330,280) -->
  <polygon points="330,220 390,280 330,280" fill="none" stroke="#000" stroke-width="3.5" stroke-dasharray="8,4" stroke-linejoin="round"/>
  <circle cx="330" cy="220" r="5" fill="#000"/>
  <circle cx="390" cy="280" r="5" fill="#000"/>
  <circle cx="330" cy="280" r="5" fill="#000"/>
  <text x="334" y="216" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">A</text>
  <text x="394" y="278" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">B</text>
  <text x="334" y="296" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">C</text>

  <!-- Spiral similarity: rotate 60° CCW and scale 0.6 about S
       A rel to S: (80,−60). Rotate 60°, scale 0.6:
       cos60=0.5,sin60=0.866
       x'=0.6*(80*0.5−(−60)*0.866)=0.6*(40+51.96)=0.6*91.96=55.17→305.2≈305
       y'=0.6*(80*0.866+(−60)*0.5)=0.6*(69.3−30)=0.6*39.3=23.6 (SVG y-down flip)
       In SVG y-down: y'=0.6*(−(−60)*0.866+80*(−0.5))=0.6*(52-40)=7.2 … 
       Let me use simpler approach for visual clarity:
       T2 is a rotated+scaled version visually placed at (180,160),(160,220),(190,220)
  -->
  <polygon points="180,158 148,228 196,228" fill="none" stroke="#000" stroke-width="3" stroke-linejoin="round"/>
  <circle cx="180" cy="158" r="5" fill="#000"/>
  <circle cx="148" cy="228" r="5" fill="#000"/>
  <circle cx="196" cy="228" r="5" fill="#000"/>
  <text x="184" y="154" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">A′</text>
  <text x="128" y="228" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">B′</text>
  <text x="198" y="244" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">C′</text>

  <!-- Spiral lines from S to each original vertex and image vertex -->
  <line x1="250" y1="280" x2="330" y2="220" stroke="#000" stroke-width="1.5" stroke-dasharray="5,3"/>
  <line x1="250" y1="280" x2="180" y2="158" stroke="#000" stroke-width="1.5" stroke-dasharray="5,3"/>
  <line x1="250" y1="280" x2="390" y2="280" stroke="#000" stroke-width="1.5" stroke-dasharray="5,3"/>
  <line x1="250" y1="280" x2="148" y2="228" stroke="#000" stroke-width="1.5" stroke-dasharray="5,3"/>

  <!-- Spiral arc (outward Archimedean-like) -->
  <path d="M 390,280 A 180,180 0 0,0 280,100" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="6,3"/>
  <path d="M 330,220 A 100,100 0 0,0 220,170" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="6,3"/>

  <!-- Scale and rotation labels -->
  <text x="310" y="242" font-family="Georgia,serif" font-size="10" fill="#000">r</text>
  <text x="202" y="210" font-family="Georgia,serif" font-size="10" fill="#000">k·r</text>
  <text x="306" y="170" font-family="Georgia,serif" font-size="10" fill="#000">θ = 60°</text>

  <!-- Formula box -->
  <rect x="30" y="360" width="430" height="120" rx="5" fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="5,3"/>
  <text x="40" y="380" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Spiral Similarity = Dilation(k) ∘ Rotation(θ), same centre</text>
  <text x="40" y="398" font-family="Georgia,serif" font-size="11" fill="#000">In ℂ:  z′ = k·e^(iθ)·(z − S) + S</text>
  <text x="40" y="416" font-family="Georgia,serif" font-size="11" fill="#000">|z′−S| = k·|z−S|   (distances scaled by k)</text>
  <text x="40" y="434" font-family="Georgia,serif" font-size="11" fill="#000">arg(z′−S) = arg(z−S) + θ  (rotated by θ)</text>
  <text x="40" y="452" font-family="Georgia,serif" font-size="11" fill="#000">Result is a SIMILAR figure: angles preserved, sides ×k</text>
  <text x="40" y="470" font-family="Georgia,serif" font-size="10" fill="#555">Dashed = pre-image · Solid = image · k &lt; 1 shown above (contraction)</text>
</svg>`;

