  // ─── 26. INVERSE TRANSFORMATION UNDO ──────────────────────────────────────
  static inverseTransformationUndoDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 500 500">

  <text x="100" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Inverse Transformations — "Undo" Operations</text>
  <text x="70" y="38" font-family="Georgia,serif" font-size="10" fill="#444">T⁻¹ ∘ T = Identity.  Each isometry has a unique inverse.</text>

  <!-- Three-box flow with forward and backward arrows -->
  <!-- Box: Pre-image -->
  <rect x="30" y="80" width="110" height="60" rx="5" fill="none" stroke="#000" stroke-width="3"/>
  <text x="50" y="107" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">△ ABC</text>
  <text x="44" y="125" font-family="Georgia,serif" font-size="9" fill="#555">pre-image</text>

  <!-- Forward arrow T -->
  <line x1="142" y1="110" x2="215" y2="110" stroke="#000" stroke-width="3"/>
  <polygon points="211,104 223,110 211,116" fill="#000"/>
  <text x="162" y="103" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">T</text>

  <!-- Box: Image -->
  <rect x="218" y="80" width="110" height="60" rx="5" fill="none" stroke="#000" stroke-width="3"/>
  <text x="232" y="107" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">△ A′B′C′</text>
  <text x="236" y="125" font-family="Georgia,serif" font-size="9" fill="#555">image</text>

  <!-- Forward arrow T -->
  <line x1="330" y1="110" x2="403" y2="110" stroke="#000" stroke-width="3"/>
  <polygon points="399,104 411,110 399,116" fill="#000"/>
  <text x="350" y="103" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">T</text>

  <!-- Box: Double image (to show T applied twice) -->
  <rect x="406" y="80" width="72" height="60" rx="5" fill="none" stroke="#000" stroke-width="3" stroke-dasharray="5,3"/>
  <text x="408" y="107" font-family="Georgia,serif" font-size="10" fill="#000">△A″B″C″</text>
  <text x="416" y="123" font-family="Georgia,serif" font-size="9" fill="#555">T²</text>

  <!-- Backward arrow T⁻¹ below -->
  <path d="M 273,142 C 273,160 185,160 185,142" fill="none" stroke="#000" stroke-width="2.5"/>
  <polygon points="188,140 176,142 188,148" fill="#000"/>
  <text x="202" y="176" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">T⁻¹ (undo T)</text>

  <!-- Identity label -->
  <text x="60" y="200" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">T⁻¹ ∘ T = T ∘ T⁻¹ = Id  (Identity)</text>

  <!-- Table of inverses -->
  <rect x="30" y="220" width="430" height="200" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="40" y="240" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Inverses of the four isometries:</text>
  <line x1="30" y1="248" x2="460" y2="248" stroke="#000" stroke-width="1.5"/>
  <line x1="230" y1="248" x2="230" y2="420" stroke="#000" stroke-width="1"/>
  <!-- headers -->
  <text x="40" y="264" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">Transformation T</text>
  <text x="238" y="264" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">Inverse T⁻¹</text>
  <line x1="30" y1="270" x2="460" y2="270" stroke="#000" stroke-width="1"/>
  <!-- rows -->
  <text x="40" y="287" font-family="Georgia,serif" font-size="11" fill="#000">Translation by v</text>
  <text x="238" y="287" font-family="Georgia,serif" font-size="11" fill="#000">Translation by −v</text>
  <text x="40" y="307" font-family="Georgia,serif" font-size="11" fill="#000">Rotation R(θ, C)</text>
  <text x="238" y="307" font-family="Georgia,serif" font-size="11" fill="#000">Rotation R(−θ, C)</text>
  <text x="40" y="327" font-family="Georgia,serif" font-size="11" fill="#000">Reflection r_ℓ</text>
  <text x="238" y="327" font-family="Georgia,serif" font-size="11" fill="#000">Reflection r_ℓ  (self-inverse!)</text>
  <text x="40" y="347" font-family="Georgia,serif" font-size="11" fill="#000">Glide refl. G = T_v ∘ r_ℓ</text>
  <text x="238" y="347" font-family="Georgia,serif" font-size="11" fill="#000">G⁻¹ = T_(−v) ∘ r_ℓ</text>
  <text x="40" y="367" font-family="Georgia,serif" font-size="11" fill="#000">Composition T₂ ∘ T₁</text>
  <text x="238" y="367" font-family="Georgia,serif" font-size="11" fill="#000">(T₂ ∘ T₁)⁻¹ = T₁⁻¹ ∘ T₂⁻¹</text>
  <text x="40" y="387" font-family="Georgia,serif" font-size="10" fill="#555">Dilation D(k, C)</text>
  <text x="238" y="387" font-family="Georgia,serif" font-size="10" fill="#555">D(1/k, C)  (not isometry)</text>
  <text x="40" y="406" font-family="Georgia,serif" font-size="9" fill="#555">Key: reflection is its own inverse (involution):  r_ℓ² = Id</text>

  <!-- Example -->
  <rect x="30" y="432" width="430" height="52" rx="4" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="5,3"/>
  <text x="40" y="450" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Example: T = R(90°,O) then T⁻¹ = R(−90°,O) = R(270°,O)</text>
  <text x="40" y="468" font-family="Georgia,serif" font-size="11" fill="#000">R(−90°)∘R(90°): (x,y)→(−y,x)→(x,y)  ✓ returns to original</text>
</svg>`;

