  // ─── 7. U-SUBSTITUTION RADICAL ────────────────────────────────────────────
  // Shows solving ∫√(ax+b) dx via u-substitution:
  //   • labelled substitution step
  //   • du/dx derivation box
  //   • rewritten integral
  //   • back-substitution
  static uSubstitutionRadicalDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 420">

  <text x="80" y="26" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">u-Substitution with Radicals  ∫√(3x+1) dx</text>
  <text x="100" y="42" font-family="Georgia,serif" font-size="10" fill="#444">Replace the radicand with u, rewrite dx in terms of du</text>

  <!-- Outer frame -->
  <rect x="30" y="54" width="460" height="340" rx="8" fill="none" stroke="#000" stroke-width="3"/>

  <!-- Step 1 -->
  <rect x="30" y="54" width="460" height="48" rx="8" fill="#ebebeb" stroke="#000" stroke-width="2.5"/>
  <text x="46" y="75" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Step 1 — Choose substitution</text>
  <text x="46" y="95" font-family="Georgia,serif" font-size="13" fill="#000">Let  u = 3x + 1</text>
  <rect x="300" y="60" width="175" height="36" rx="4" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="5,3"/>
  <text x="308" y="76" font-family="Georgia,serif" font-size="10" fill="#000">Choose u = (inner function)</text>
  <text x="308" y="90" font-family="Georgia,serif" font-size="10" fill="#000">i.e. the radicand 3x+1</text>

  <!-- Step 2 -->
  <line x1="30" y1="102" x2="490" y2="102" stroke="#000" stroke-width="1.8"/>
  <text x="46" y="122" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Step 2 — Differentiate u with respect to x</text>
  <text x="46" y="142" font-family="Georgia,serif" font-size="13" fill="#000">du/dx = 3   →   dx = du/3</text>
  <!-- d/dx annotation -->
  <path d="M160,128 C175,115 220,115 240,128" fill="none" stroke="#000" stroke-width="1.6" stroke-dasharray="3,2"/>
  <text x="170" y="112" font-family="Georgia,serif" font-size="9" fill="#555">differentiate</text>

  <!-- Step 3 -->
  <line x1="30" y1="154" x2="490" y2="154" stroke="#000" stroke-width="1.8"/>
  <text x="46" y="174" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Step 3 — Rewrite integral in terms of u</text>
  <text x="46" y="196" font-family="Georgia,serif" font-size="13" fill="#000">∫√(3x+1) dx  =  ∫√u · (du/3)</text>
  <text x="46" y="216" font-family="Georgia,serif" font-size="13" fill="#000">             =  (1/3)·∫u^(1/2) du</text>

  <!-- Step 4 -->
  <line x1="30" y1="228" x2="490" y2="228" stroke="#000" stroke-width="1.8"/>
  <text x="46" y="248" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Step 4 — Integrate using power rule  ∫uⁿ du = u^(n+1)/(n+1)</text>
  <text x="46" y="270" font-family="Georgia,serif" font-size="13" fill="#000">(1/3)·[u^(3/2) / (3/2)]  +  C</text>
  <text x="46" y="290" font-family="Georgia,serif" font-size="13" fill="#000">=  (1/3)·(2/3)·u^(3/2)  +  C</text>
  <text x="46" y="310" font-family="Georgia,serif" font-size="13" fill="#000">=  (2/9)·u^(3/2)  +  C</text>

  <!-- Step 5 -->
  <line x1="30" y1="322" x2="490" y2="322" stroke="#000" stroke-width="1.8"/>
  <text x="46" y="342" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Step 5 — Back-substitute  u = 3x+1</text>
  <text x="46" y="362" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">∫√(3x+1) dx  =  (2/9)(3x+1)^(3/2)  +  C</text>

  <!-- Back-sub arrow -->
  <path d="M 170,348 C 200,332 260,332 290,348" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="4,3"/>
  <text x="205" y="330" font-family="Georgia,serif" font-size="9" fill="#555">replace u</text>

  <!-- box around answer -->
  <rect x="38" y="352" width="444" height="30" rx="4" fill="none" stroke="#000" stroke-width="3"/>
</svg>`;

