  // ─── 20. POLYNOMIAL INTERSECTION ─────────────────────────────────────────
  // Shows two polynomials intersecting, with method to find intersection points
  static polynomialIntersectionDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 540 420">

  <!-- Title -->
  <text x="90" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Polynomial Intersection — Finding Common Points</text>
  <text x="110" y="38" font-family="Georgia,serif" font-size="10" fill="#444">Set f(x) = g(x)  →  solve h(x) = f(x) − g(x) = 0</text>

  <!-- Coordinate axes -->
  <line x1="50" y1="240" x2="490" y2="240" stroke="#000" stroke-width="2"/>
  <polygon points="486,235 498,240 486,245" fill="#000"/>
  <text x="500" y="244" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">x</text>
  <line x1="270" y1="60" x2="270" y2="310" stroke="#000" stroke-width="2"/>
  <polygon points="265,64 270,52 275,64" fill="#000"/>
  <text x="275" y="50" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">y</text>

  <!-- Curve f(x) = x² − 2 (parabola) -->
  <path d="M100,290 Q270,120 440,290" fill="none" stroke="#000" stroke-width="3"/>
  <!-- f(x) label -->
  <text x="445" y="285" font-family="Georgia,serif" font-size="12" font-weight="bold" font-style="italic" fill="#000">f(x)=x²−2</text>

  <!-- Curve g(x) = x+1 (line) -->
  <line x1="80" y1="290" x2="460" y2="150" stroke="#000" stroke-width="2.5" stroke-dasharray="7,4"/>
  <text x="462" y="147" font-family="Georgia,serif" font-size="12" font-weight="bold" font-style="italic" fill="#000">g(x)=x+1</text>

  <!-- Intersection points: x²−2=x+1 → x²−x−3=0 → x=(1±√13)/2 ≈ −1.30 and 2.30 -->
  <!-- Point 1 at approx (−1.30, −0.30) → pixel (200, 245) approx -->
  <circle cx="200" cy="243" r="7" fill="#000"/>
  <line x1="200" y1="243" x2="200" y2="310" stroke="#000" stroke-width="1.2" stroke-dasharray="4,3"/>
  <text x="168" y="325" font-family="Georgia,serif" font-size="10" fill="#000">x₁≈−1.30</text>

  <!-- Point 2 at approx x=2.30 → pixel (345,245) -->
  <circle cx="348" cy="240" r="7" fill="#000"/>
  <line x1="348" y1="240" x2="348" y2="310" stroke="#000" stroke-width="1.2" stroke-dasharray="4,3"/>
  <text x="334" y="325" font-family="Georgia,serif" font-size="10" fill="#000">x₂≈2.30</text>

  <!-- Method box -->
  <rect x="40" y="340" width="470" height="70" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="55" y="358" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Method:  Set f(x) = g(x):</text>
  <text x="55" y="376" font-family="Georgia,serif" font-size="11" fill="#000">x²−2 = x+1  →  x²−x−3 = 0  →  x = (1 ± √13) / 2</text>
  <text x="55" y="394" font-family="Georgia,serif" font-size="10" fill="#000">Substitute back:  y = x+1  →  Points: ((1−√13)/2, (3−√13)/2) and ((1+√13)/2, (3+√13)/2)</text>
</svg>`;

