  // ─── 22. RATIONAL EXPRESSION ANATOMY ──────────────────────────────────────
  // Labels numerator, denominator, domain restrictions on a sample rational expression
  static rationalExpressionAnatomyDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 540 400">

  <!-- Title -->
  <text x="90" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Anatomy of a Rational Expression</text>

  <!-- Main expression: (3x²+5x−2) / (x²−4) -->
  <!-- Fraction bar -->
  <line x1="90" y1="115" x2="400" y2="115" stroke="#000" stroke-width="4"/>

  <!-- Numerator -->
  <text x="95" y="105" font-family="Georgia,serif" font-size="28" font-weight="bold" fill="#000">3x² + 5x − 2</text>

  <!-- Denominator -->
  <text x="155" y="150" font-family="Georgia,serif" font-size="28" font-weight="bold" fill="#000">x² − 4</text>

  <!-- Callout: Numerator -->
  <line x1="220" y1="90" x2="220" y2="70" stroke="#000" stroke-width="1.8"/>
  <line x1="220" y1="70" x2="430" y2="60" stroke="#000" stroke-width="1.8"/>
  <circle cx="220" cy="90" r="3" fill="#000"/>
  <text x="432" y="58" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">Numerator: P(x) = 3x²+5x−2</text>
  <text x="432" y="70" font-family="Georgia,serif" font-size="9" fill="#000">= (3x−1)(x+2)  ← can be factored</text>

  <!-- Callout: Denominator -->
  <line x1="230" y1="140" x2="230" y2="175" stroke="#000" stroke-width="1.8"/>
  <line x1="230" y1="175" x2="430" y2="190" stroke="#000" stroke-width="1.8"/>
  <circle cx="230" cy="140" r="3" fill="#000"/>
  <text x="432" y="188" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">Denominator: Q(x) = x²−4</text>
  <text x="432" y="200" font-family="Georgia,serif" font-size="9" fill="#000">= (x−2)(x+2)  ← difference of squares</text>

  <!-- Fraction bar callout -->
  <line x1="400" y1="115" x2="430" y2="115" stroke="#000" stroke-width="1.8"/>
  <text x="432" y="119" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">Fraction bar (division)</text>

  <!-- Domain restriction box -->
  <rect x="40" y="218" width="470" height="65" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="55" y="236" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Domain restrictions: Q(x) ≠ 0</text>
  <text x="55" y="254" font-family="Georgia,serif" font-size="11" fill="#000">x²−4 = 0  →  x = ±2  ← excluded from domain</text>
  <text x="55" y="272" font-family="Georgia,serif" font-size="10" fill="#000">Domain:  x ∈ ℝ,  x ≠ −2,  x ≠ 2    (or in interval notation: (−∞,−2)∪(−2,2)∪(2,+∞))</text>

  <!-- Simplification box -->
  <rect x="40" y="296" width="470" height="90" rx="5" fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="5,3"/>
  <text x="55" y="314" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Simplification (cancel common factors):</text>
  <text x="55" y="332" font-family="Georgia,serif" font-size="12" fill="#000">(3x−1)(x+2)     3x−1</text>
  <line x1="55" y1="336" x2="240" y2="336" stroke="#000" stroke-width="1.5"/>
  <text x="55" y="352" font-family="Georgia,serif" font-size="12" fill="#000">(x−2)(x+2)   =   x−2</text>
  <text x="260" y="344" font-family="Georgia,serif" font-size="10" fill="#000">← (x+2) cancelled; x≠−2 still excluded!</text>
  <text x="55" y="370" font-family="Georgia,serif" font-size="9" fill="#444">Hole at x=−2 (removable discontinuity)   |   Vertical asymptote at x=2</text>
  <text x="55" y="382" font-family="Georgia,serif" font-size="9" fill="#444">Cancellation is ONLY valid when noting the excluded value remains excluded</text>
</svg>`;

  // ─── 23. FACTOR-CANCEL DIAGRAM ────────────────────────────────────────────
