  // ─── 24. CLEARING DENOMINATORS FLOWCHART ─────────────────────────────────
  // Step-by-step process for solving rational equations by clearing denominators
  static clearingDenominatorsFlowchartsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 460">

  <!-- Title -->
  <text x="80" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Clearing Denominators — Solving Rational Equations</text>

  <!-- Step 1 -->
  <rect x="60" y="45" width="400" height="44" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="75" y="63" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Step 1 — Identify all denominators:</text>
  <text x="75" y="81" font-family="Georgia,serif" font-size="11" fill="#000">Example:  2/(x−1) + 3/(x+2) = 1</text>
  <text x="470" y="70" font-family="Georgia,serif" font-size="10" fill="#000">denoms: (x−1), (x+2)</text>

  <line x1="260" y1="89" x2="260" y2="108" stroke="#000" stroke-width="2"/>
  <polygon points="256,104 260,114 264,104" fill="#000"/>

  <!-- Step 2 -->
  <rect x="60" y="108" width="400" height="44" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="75" y="126" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Step 2 — Find LCD (Least Common Denominator):</text>
  <text x="75" y="144" font-family="Georgia,serif" font-size="11" fill="#000">LCD = (x−1)(x+2)   ← product when no common factors</text>

  <line x1="260" y1="152" x2="260" y2="171" stroke="#000" stroke-width="2"/>
  <polygon points="256,167 260,177 264,167" fill="#000"/>

  <!-- Step 3 -->
  <rect x="60" y="171" width="400" height="44" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="75" y="189" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Step 3 — Multiply every term by LCD:</text>
  <text x="75" y="207" font-family="Georgia,serif" font-size="11" fill="#000">2(x+2) + 3(x−1) = (x−1)(x+2)</text>

  <line x1="260" y1="215" x2="260" y2="234" stroke="#000" stroke-width="2"/>
  <polygon points="256,230 260,240 264,230" fill="#000"/>

  <!-- Step 4 -->
  <rect x="60" y="234" width="400" height="44" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="75" y="252" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Step 4 — Expand and simplify:</text>
  <text x="75" y="270" font-family="Georgia,serif" font-size="11" fill="#000">2x+4+3x−3 = x²+x−2  →  5x+1 = x²+x−2  →  x²−4x−3=0</text>

  <line x1="260" y1="278" x2="260" y2="297" stroke="#000" stroke-width="2"/>
  <polygon points="256,293 260,303 264,293" fill="#000"/>

  <!-- Step 5 -->
  <rect x="60" y="297" width="400" height="44" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="75" y="315" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Step 5 — Solve resulting polynomial equation:</text>
  <text x="75" y="333" font-family="Georgia,serif" font-size="11" fill="#000">x²−4x−3=0  →  x = (4 ± √28)/2 = 2 ± √7</text>

  <line x1="260" y1="341" x2="260" y2="360" stroke="#000" stroke-width="2"/>
  <polygon points="256,356 260,366 264,356" fill="#000"/>

  <!-- Step 6: Check extraneous -->
  <rect x="60" y="360" width="400" height="55" rx="5" fill="none" stroke="#000" stroke-width="3"/>
  <text x="75" y="378" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Step 6 — CHECK for extraneous solutions:</text>
  <text x="75" y="396" font-family="Georgia,serif" font-size="11" fill="#000">x ≠ 1 and x ≠ 2  (original denominators = 0)</text>
  <text x="75" y="410" font-family="Georgia,serif" font-size="10" fill="#444">x = 2±√7 ≈ 4.65 or −0.65  → neither equals 1 or −2  ✓</text>

  <!-- Warning callout -->
  <rect x="465" y="350" width="60" height="50" rx="5" fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="4,3"/>
  <text x="470" y="368" font-family="Georgia,serif" font-size="9" font-weight="bold" fill="#000">⚠ Always</text>
  <text x="470" y="381" font-family="Georgia,serif" font-size="9" fill="#000">check for</text>
  <text x="470" y="393" font-family="Georgia,serif" font-size="9" fill="#000">extraneous</text>
</svg>`;

