  // ─── 9. CUBE IDENTITY STEP DIAGRAM ────────────────────────────────────────
  // Step-by-step worked example factoring 8x³ − 27 using difference of cubes
  static cubeIdentityStepDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 460">

  <!-- Title -->
  <text x="100" y="24" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Cube Identity — Step-by-Step Example</text>
  <text x="90" y="40" font-family="Georgia,serif" font-size="10" fill="#444">Factor  8x³ − 27  using the difference of cubes identity</text>

  <!-- Step 1 -->
  <rect x="40" y="54" width="440" height="52" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="52" y="72" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Step 1 — Write each term as a perfect cube</text>
  <text x="52" y="94" font-family="Georgia,serif" font-size="13" fill="#000">8x³ = (2x)³       27 = 3³</text>
  <!-- bracket annotations -->
  <path d="M66,98 L66,108 L120,108 L120,98" fill="none" stroke="#000" stroke-width="1.5"/>
  <text x="72" y="120" font-family="Georgia,serif" font-size="9" fill="#555">a = 2x</text>
  <path d="M196,98 L196,108 L230,108 L230,98" fill="none" stroke="#000" stroke-width="1.5"/>
  <text x="200" y="120" font-family="Georgia,serif" font-size="9" fill="#555">b = 3</text>

  <!-- Arrow -->
  <line x1="260" y1="128" x2="260" y2="146" stroke="#000" stroke-width="2.5"/>
  <polygon points="254,142 260,154 266,142" fill="#000"/>

  <!-- Step 2 -->
  <rect x="40" y="154" width="440" height="52" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="52" y="172" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Step 2 — Apply  a³ − b³ = (a−b)(a²+ab+b²)</text>
  <text x="52" y="194" font-family="Georgia,serif" font-size="13" fill="#000">= (2x − 3)[(2x)² + (2x)(3) + 3²]</text>

  <!-- Arrow -->
  <line x1="260" y1="210" x2="260" y2="228" stroke="#000" stroke-width="2.5"/>
  <polygon points="254,224 260,236 266,224" fill="#000"/>

  <!-- Step 3 -->
  <rect x="40" y="236" width="440" height="52" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="52" y="254" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Step 3 — Simplify the quadratic factor</text>
  <text x="52" y="276" font-family="Georgia,serif" font-size="13" fill="#000">= (2x − 3)[4x² + 6x + 9]</text>
  <!-- annotation arrows -->
  <line x1="156" y1="280" x2="180" y2="296" stroke="#000" stroke-width="1.5" stroke-dasharray="3,2"/>
  <text x="120" y="308" font-family="Georgia,serif" font-size="9" fill="#555">(2x)²=4x²</text>
  <line x1="238" y1="280" x2="245" y2="296" stroke="#000" stroke-width="1.5" stroke-dasharray="3,2"/>
  <text x="220" y="308" font-family="Georgia,serif" font-size="9" fill="#555">2·2x·3=6x</text>
  <line x1="290" y1="280" x2="296" y2="296" stroke="#000" stroke-width="1.5" stroke-dasharray="3,2"/>
  <text x="278" y="308" font-family="Georgia,serif" font-size="9" fill="#555">3²=9</text>

  <!-- Arrow -->
  <line x1="260" y1="316" x2="260" y2="334" stroke="#000" stroke-width="2.5"/>
  <polygon points="254,330 260,342 266,330" fill="#000"/>

  <!-- Result -->
  <rect x="40" y="342" width="440" height="46" rx="4" fill="none" stroke="#000" stroke-width="3"/>
  <text x="52" y="362" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Final Answer:</text>
  <text x="52" y="380" font-family="Georgia,serif" font-size="15" font-weight="bold" fill="#000">8x³ − 27  =  (2x − 3)(4x² + 6x + 9)</text>

  <!-- Note on irreducibility -->
  <rect x="40" y="400" width="440" height="46" rx="4" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="5,3"/>
  <text x="52" y="418" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">Note — Is (4x²+6x+9) factorable further?</text>
  <text x="52" y="436" font-family="Georgia,serif" font-size="10" fill="#555">Discriminant: b²−4ac = 36−144 = −108 &lt; 0  →  No real roots  →  Irreducible over ℝ</text>
</svg>`;

  // ─── 10. DISCRIMINANT TEST CUBES TRINOMIAL ─────────────────────────────────
  // Discriminant b²-4ac applied to check irreducibility of quadratic factors
  static discriminantTestCubesTrinomialsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 440">

  <!-- Title -->
  <text x="70" y="24" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Discriminant Test — Cube Identity Quadratic Factors</text>
  <text x="60" y="40" font-family="Georgia,serif" font-size="10" fill="#444">Proving that a²±ab+b² is always irreducible over ℝ when a,b≠0</text>

  <!-- Formula box -->
  <rect x="40" y="52" width="440" height="54" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="52" y="72" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Quadratic factor from cube identities:  a²+ab+b²</text>
  <text x="52" y="92" font-family="Georgia,serif" font-size="11" fill="#000">Treat as quadratic in a:   A=1, B=b, C=b²</text>

  <!-- Discriminant calculation -->
  <rect x="40" y="120" width="440" height="84" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="52" y="138" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Discriminant Δ = B² − 4AC</text>
  <line x1="40" y1="144" x2="480" y2="144" stroke="#000" stroke-width="1.5"/>
  <text x="52" y="162" font-family="Georgia,serif" font-size="12" fill="#000">Δ = b² − 4(1)(b²)</text>
  <text x="52" y="180" font-family="Georgia,serif" font-size="12" fill="#000">Δ = b² − 4b²  =  −3b²</text>
  <text x="52" y="198" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Δ = −3b²  &lt;  0  for all  b ≠ 0</text>
  <!-- annotation -->
  <path d="M310,190 C370,180 420,180 460,190" fill="none" stroke="#000" stroke-width="1.5" stroke-dasharray="4,2"/>
  <text x="360" y="174" font-family="Georgia,serif" font-size="9" fill="#555">always negative</text>

  <!-- Interpretation box -->
  <rect x="40" y="220" width="440" height="64" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="52" y="238" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Interpretation:</text>
  <text x="52" y="256" font-family="Georgia,serif" font-size="11" fill="#000">Δ &lt; 0  →  No real roots  →  Cannot factor over ℝ</text>
  <text x="52" y="274" font-family="Georgia,serif" font-size="11" fill="#000">Therefore a²+ab+b² is always irreducible over the reals</text>

  <!-- Same test for a²-ab+b² -->
  <rect x="40" y="300" width="440" height="84" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="52" y="318" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Similarly for  a²−ab+b²  (from sum of cubes)</text>
  <line x1="40" y1="324" x2="480" y2="324" stroke="#000" stroke-width="1.5"/>
  <text x="52" y="342" font-family="Georgia,serif" font-size="12" fill="#000">A=1, B=−b, C=b²</text>
  <text x="52" y="360" font-family="Georgia,serif" font-size="12" fill="#000">Δ = (−b)² − 4b² = b² − 4b² = −3b²  &lt;  0</text>
  <text x="52" y="378" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Also irreducible over ℝ  ✓</text>

  <!-- Summary -->
  <rect x="40" y="400" width="440" height="30" rx="4" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="5,3"/>
  <text x="52" y="420" font-family="Georgia,serif" font-size="10" fill="#555">Rule: After applying a cube identity, the quadratic factor never factors further over ℝ</text>
</svg>`;

