  // ─── 14. IRREDUCIBLE FACTOR DEFINITION ─────────────────────────────────────
  // Defines irreducible polynomial with examples and non-examples
  static irreducibleFactorDefinitionDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 420">

  <!-- Title -->
  <text x="90" y="24" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Irreducible Polynomial — Definition &amp; Examples</text>

  <!-- Definition box -->
  <rect x="40" y="40" width="440" height="64" rx="5" fill="none" stroke="#000" stroke-width="3"/>
  <text x="52" y="58" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Definition</text>
  <text x="52" y="76" font-family="Georgia,serif" font-size="11" fill="#000">A polynomial p(x) is irreducible over ℝ if it cannot be written</text>
  <text x="52" y="94" font-family="Georgia,serif" font-size="11" fill="#000">as a product of two polynomials of lower degree with real coefficients.</text>

  <!-- Two-column: Reducible vs Irreducible -->
  <!-- Reducible header -->
  <rect x="40" y="120" width="210" height="28" rx="3" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="68" y="138" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Reducible  ✗</text>

  <!-- Irreducible header -->
  <rect x="270" y="120" width="210" height="28" rx="3" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="296" y="138" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Irreducible  ✓</text>

  <!-- Dividing line -->
  <line x1="255" y1="116" x2="255" y2="390" stroke="#000" stroke-width="2" stroke-dasharray="6,4"/>

  <!-- Reducible examples -->
  <text x="48" y="174" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">x² − 4</text>
  <text x="48" y="190" font-family="Georgia,serif" font-size="10" fill="#555">= (x−2)(x+2)   factors!</text>

  <text x="48" y="220" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">x² + 5x + 6</text>
  <text x="48" y="236" font-family="Georgia,serif" font-size="10" fill="#555">= (x+2)(x+3)   Δ=1&gt;0</text>

  <text x="48" y="266" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">x³ − 8</text>
  <text x="48" y="282" font-family="Georgia,serif" font-size="10" fill="#555">= (x−2)(x²+2x+4)</text>

  <text x="48" y="312" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">6x² + 7x + 2</text>
  <text x="48" y="328" font-family="Georgia,serif" font-size="10" fill="#555">= (2x+1)(3x+2)</text>

  <!-- Irreducible examples -->
  <text x="278" y="174" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">x² + 4</text>
  <text x="278" y="190" font-family="Georgia,serif" font-size="10" fill="#555">Δ = 0−16 = −16 &lt; 0  no real roots</text>

  <text x="278" y="220" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">x² + x + 1</text>
  <text x="278" y="236" font-family="Georgia,serif" font-size="10" fill="#555">Δ = 1−4 = −3 &lt; 0</text>

  <text x="278" y="266" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">x² − x + 1</text>
  <text x="278" y="282" font-family="Georgia,serif" font-size="10" fill="#555">Δ = 1−4 = −3 &lt; 0</text>

  <text x="278" y="312" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">x + 5</text>
  <text x="278" y="328" font-family="Georgia,serif" font-size="10" fill="#555">Degree 1 → always irreducible</text>

  <!-- Test rule -->
  <rect x="40" y="350" width="440" height="52" rx="4" fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="5,3"/>
  <text x="52" y="368" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Quick Test — Quadratic ax²+bx+c is irreducible over ℝ iff:</text>
  <text x="52" y="390" font-family="Georgia,serif" font-size="11" fill="#000">Discriminant  Δ = b² − 4ac  &lt;  0</text>
</svg>`;

