  static rationalRootTheoremDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 460">

  <!-- Title -->
  <text x="90" y="24" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Rational Root Theorem</text>
  <text x="60" y="40" font-family="Georgia,serif" font-size="10" fill="#444">Possible rational roots of  2x³ − 3x² − 11x + 6  are  ±(factors of 6)/(factors of 2)</text>

  <!-- Theorem statement -->
  <rect x="40" y="52" width="440" height="54" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="52" y="68" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Theorem: If  aₙxⁿ+…+a₀  has rational root p/q (in lowest terms), then:</text>
  <text x="52" y="88" font-family="Georgia,serif" font-size="12" fill="#000">p  |  a₀  (constant term)    and    q  |  aₙ  (leading coefficient)</text>

  <!-- Candidate list -->
  <rect x="40" y="120" width="440" height="70" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="52" y="138" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Candidates for  2x³−3x²−11x+6:</text>
  <text x="52" y="156" font-family="Georgia,serif" font-size="11" fill="#000">Factors of 6:  ±1, ±2, ±3, ±6</text>
  <text x="52" y="174" font-family="Georgia,serif" font-size="11" fill="#000">Factors of 2:  ±1, ±2  →  Candidates: ±1, ±2, ±3, ±6, ±½, ±³⁄₂</text>

  <!-- Synthetic division for x=3 -->
  <rect x="40" y="206" width="440" height="100" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="52" y="224" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Test x = 3  via synthetic division:</text>
  <line x1="52" y1="232" x2="470" y2="232" stroke="#000" stroke-width="1.5"/>
  <!-- Coefficients row -->
  <text x="90" y="252" font-family="Georgia,serif" font-size="12" fill="#000">2</text>
  <text x="180" y="252" font-family="Georgia,serif" font-size="12" fill="#000">−3</text>
  <text x="270" y="252" font-family="Georgia,serif" font-size="12" fill="#000">−11</text>
  <text x="370" y="252" font-family="Georgia,serif" font-size="12" fill="#000">6</text>
  <text x="54" y="252" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">3 |</text>
  <!-- Bring-down row -->
  <line x1="80" y1="258" x2="470" y2="258" stroke="#000" stroke-width="1.5"/>
  <text x="130" y="274" font-family="Georgia,serif" font-size="11" fill="#555">6</text>
  <text x="210" y="274" font-family="Georgia,serif" font-size="11" fill="#555">9</text>
  <text x="300" y="274" font-family="Georgia,serif" font-size="11" fill="#555">−6</text>
  <text x="90" y="290" font-family="Georgia,serif" font-size="12" fill="#000">2</text>
  <text x="175" y="290" font-family="Georgia,serif" font-size="12" fill="#000">3</text>
  <text x="265" y="290" font-family="Georgia,serif" font-size="12" fill="#000">−2</text>
  <text x="370" y="290" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">0 ←remainder=0 ✓</text>

  <!-- Result -->
  <rect x="40" y="320" width="440" height="54" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="52" y="338" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Quotient: 2x²+3x−2  →  factor further:</text>
  <text x="52" y="360" font-family="Georgia,serif" font-size="12" fill="#000">2x²+3x−2 = (2x−1)(x+2)</text>

  <!-- Final factored form -->
  <rect x="40" y="390" width="440" height="54" rx="4" fill="none" stroke="#000" stroke-width="3"/>
  <text x="52" y="408" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Complete factorization:</text>
  <text x="52" y="432" font-family="Georgia,serif" font-size="13" fill="#000">2x³−3x²−11x+6  =  (x−3)(2x−1)(x+2)</text>
</svg>`;

