  // ─── 25. TWO-STEP SOLVING FLOWCHART ───────────────────────────────────────
  // Flowchart for solving ax + b = c
  static twoStepSolvingFlowchartsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 460">

  <!-- Title -->
  <text x="100" y="24" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Two-Step Equation Solving Flowchart</text>
  <text x="90" y="40" font-family="Georgia,serif" font-size="10" fill="#444">Strategy for solving  ax + b = c</text>

  <!-- Equation display -->
  <rect x="180" y="52" width="160" height="38" rx="5" fill="none" stroke="#000" stroke-width="3"/>
  <text x="196" y="76" font-family="Georgia,serif" font-size="16" font-weight="bold" fill="#000">ax + b = c</text>

  <!-- Arrow 1 -->
  <line x1="260" y1="90" x2="260" y2="116" stroke="#000" stroke-width="2.5"/>
  <polygon points="254,112 260,124 266,112" fill="#000"/>
  <text x="264" y="108" font-family="Georgia,serif" font-size="9" fill="#555">Step 1</text>

  <!-- Step 1 box: undo addition/subtraction -->
  <rect x="80" y="124" width="360" height="54" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="92" y="142" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Isolate the variable term  (ax)</text>
  <text x="92" y="160" font-family="Georgia,serif" font-size="11" fill="#000">Subtract b from both sides:   ax + b − b = c − b</text>
  <text x="92" y="172" font-family="Georgia,serif" font-size="11" fill="#555">→   ax = c − b</text>

  <!-- Arrow 2 -->
  <line x1="260" y1="178" x2="260" y2="204" stroke="#000" stroke-width="2.5"/>
  <polygon points="254,200 260,212 266,200" fill="#000"/>
  <text x="264" y="196" font-family="Georgia,serif" font-size="9" fill="#555">Step 2</text>

  <!-- Step 2 box: undo multiplication -->
  <rect x="80" y="212" width="360" height="54" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="92" y="230" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Isolate x  (remove coefficient a)</text>
  <text x="92" y="248" font-family="Georgia,serif" font-size="11" fill="#000">Divide both sides by a:   ax/a = (c−b)/a</text>
  <text x="92" y="262" font-family="Georgia,serif" font-size="11" fill="#555">→   x = (c − b) / a</text>

  <!-- Arrow 3 -->
  <line x1="260" y1="266" x2="260" y2="292" stroke="#000" stroke-width="2.5"/>
  <polygon points="254,288 260,300 266,288" fill="#000"/>

  <!-- Worked example -->
  <rect x="80" y="300" width="360" height="100" rx="4" fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="5,3"/>
  <text x="92" y="318" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Worked example:  3x + 7 = 22</text>
  <line x1="80" y1="324" x2="440" y2="324" stroke="#000" stroke-width="1.5"/>
  <text x="92" y="342" font-family="Georgia,serif" font-size="11" fill="#000">Step 1:  3x + 7 − 7 = 22 − 7   →   3x = 15</text>
  <text x="92" y="362" font-family="Georgia,serif" font-size="11" fill="#000">Step 2:  3x ÷ 3 = 15 ÷ 3       →   x = 5</text>
  <text x="92" y="382" font-family="Georgia,serif" font-size="11" fill="#555">Check: 3(5)+7 = 15+7 = 22  ✓</text>

  <!-- Check reminder -->
  <rect x="80" y="416" width="360" height="32" rx="4" fill="none" stroke="#000" stroke-width="2"/>
  <text x="92" y="436" font-family="Georgia,serif" font-size="11" fill="#000">Always substitute back to verify your answer!</text>
</svg>`;

