  // ─── 29. FORMULA REARRANGEMENT ──────────────────────────────────────────────
  // v = u + at rearranged for each variable with step annotations
  static formulaRearrangementDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 460">

  <!-- Title -->
  <text x="80" y="24" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Formula Rearrangement — Making Different Subjects</text>
  <text x="90" y="40" font-family="Georgia,serif" font-size="10" fill="#444">Formula:  v = u + at   (kinematics equation)</text>

  <!-- Original formula -->
  <rect x="190" y="52" width="140" height="36" rx="5" fill="none" stroke="#000" stroke-width="3"/>
  <text x="198" y="76" font-family="Georgia,serif" font-size="16" font-weight="bold" fill="#000">v = u + at</text>

  <!-- Make u the subject -->
  <rect x="30" y="120" width="210" height="104" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="42" y="138" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Make u the subject:</text>
  <text x="42" y="158" font-family="Georgia,serif" font-size="11" fill="#000">v = u + at</text>
  <text x="42" y="176" font-family="Georgia,serif" font-size="11" fill="#555">subtract at from both sides:</text>
  <text x="42" y="196" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">u = v − at</text>
  <line x1="30" y1="200" x2="240" y2="200" stroke="#000" stroke-width="1"/>
  <text x="42" y="216" font-family="Georgia,serif" font-size="9" fill="#555">Note: only one step needed</text>

  <!-- Make a the subject -->
  <rect x="280" y="120" width="210" height="120" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="292" y="138" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Make a the subject:</text>
  <text x="292" y="158" font-family="Georgia,serif" font-size="11" fill="#000">v = u + at</text>
  <text x="292" y="176" font-family="Georgia,serif" font-size="11" fill="#555">step 1: v − u = at</text>
  <text x="292" y="194" font-family="Georgia,serif" font-size="11" fill="#555">step 2: (v−u)/t = a</text>
  <text x="292" y="214" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">a = (v − u) / t</text>
  <line x1="280" y1="220" x2="490" y2="220" stroke="#000" stroke-width="1"/>
  <text x="292" y="232" font-family="Georgia,serif" font-size="9" fill="#555">Two steps: sub then divide</text>

  <!-- Make t the subject -->
  <rect x="30" y="256" width="440" height="106" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="42" y="274" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Make t the subject:</text>
  <text x="42" y="294" font-family="Georgia,serif" font-size="11" fill="#000">v = u + at</text>
  <text x="180" y="294" font-family="Georgia,serif" font-size="11" fill="#555">step 1: v − u = at   (subtract u)</text>
  <text x="42" y="314" font-family="Georgia,serif" font-size="11" fill="#000">v − u = at</text>
  <text x="180" y="314" font-family="Georgia,serif" font-size="11" fill="#555">step 2: (v−u)/a = t   (divide by a)</text>
  <text x="42" y="340" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">t = (v − u) / a      (a ≠ 0)</text>

  <!-- Rules summary -->
  <rect x="30" y="378" width="460" height="68" rx="4" fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="5,3"/>
  <text x="42" y="396" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">General Rules for Rearranging:</text>
  <text x="42" y="414" font-family="Georgia,serif" font-size="10" fill="#000">1. Identify what you want to isolate (the new subject)</text>
  <text x="42" y="430" font-family="Georgia,serif" font-size="10" fill="#000">2. Apply inverse operations in reverse order (BODMAS in reverse) to both sides</text>
  <text x="42" y="446" font-family="Georgia,serif" font-size="10" fill="#555">3. Note any restrictions (division by zero; square root requires ± )</text>
</svg>`;

