  // ─── 34. RATE DISTANCE TIME DIAGRAM ────────────────────────────────────────
  // D = R × T triangle, formula rearrangements, worked example
  static rateDistanceTimeDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 520 420">

  <!-- Title -->
  <text x="90" y="24" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Rate, Distance &amp; Time — Formula Triangle</text>

  <!-- Big triangle -->
  <polygon points="260,52 160,196 360,196" fill="none" stroke="#000" stroke-width="4"/>

  <!-- D at top -->
  <text x="240" y="90" font-family="Georgia,serif" font-size="28" font-weight="bold" fill="#000">D</text>
  <!-- Dividing line -->
  <line x1="160" y1="148" x2="360" y2="148" stroke="#000" stroke-width="3"/>
  <!-- R and T at bottom -->
  <text x="180" y="186" font-family="Georgia,serif" font-size="22" font-weight="bold" fill="#000">R</text>
  <text x="308" y="186" font-family="Georgia,serif" font-size="22" font-weight="bold" fill="#000">T</text>
  <!-- Vertical divide between R and T -->
  <line x1="260" y1="148" x2="260" y2="196" stroke="#000" stroke-width="3"/>

  <!-- Labels under triangle -->
  <text x="155" y="214" font-family="Georgia,serif" font-size="11" fill="#555">Rate (speed)</text>
  <text x="280" y="214" font-family="Georgia,serif" font-size="11" fill="#555">Time</text>
  <text x="215" y="50" font-family="Georgia,serif" font-size="11" fill="#555">Distance</text>

  <!-- Three formula boxes -->
  <rect x="30" y="232" width="140" height="62" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="42" y="250" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Cover D:</text>
  <text x="42" y="276" font-family="Georgia,serif" font-size="16" font-weight="bold" fill="#000">D = R × T</text>

  <rect x="190" y="232" width="140" height="62" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="202" y="250" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Cover R:</text>
  <text x="202" y="276" font-family="Georgia,serif" font-size="16" font-weight="bold" fill="#000">R = D / T</text>

  <rect x="350" y="232" width="140" height="62" rx="4" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="362" y="250" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Cover T:</text>
  <text x="362" y="276" font-family="Georgia,serif" font-size="16" font-weight="bold" fill="#000">T = D / R</text>

  <!-- Worked example -->
  <rect x="30" y="310" width="460" height="94" rx="4" fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="5,3"/>
  <text x="42" y="328" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Worked example:</text>
  <text x="42" y="346" font-family="Georgia,serif" font-size="11" fill="#000">A car travels 150 km at 60 km/h.  How long does the journey take?</text>
  <text x="42" y="364" font-family="Georgia,serif" font-size="11" fill="#000">T = D / R  =  150 / 60  =  2.5 hours</text>
  <text x="42" y="382" font-family="Georgia,serif" font-size="11" fill="#000">= 2 hours 30 minutes</text>
  <text x="42" y="398" font-family="Georgia,serif" font-size="10" fill="#555">Units check: km ÷ (km/h) = h  ✓</text>
</svg>`;

