  // ─── 5. COMPLETING THE SQUARE ──────────────────────────────────────────────
  static completingTheSquareAlgebraicStepsVertexFormDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="700px" height="500px" viewBox="0 0 580 480">

  <text x="120" y="24" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Completing the Square — Steps &amp; Vertex Form</text>

  <!-- Step boxes connected by arrows -->
  <!-- Step 1 -->
  <rect x="40" y="50" width="500" height="52" rx="6" fill="none" stroke="#000" stroke-width="3"/>
  <text x="56" y="72" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Step 1 — Start with standard form:</text>
  <text x="56" y="92" font-family="Georgia,serif" font-size="13" fill="#000">y  =  ax² + bx + c      [example:  y = x² + 6x + 2]</text>

  <!-- Arrow -->
  <line x1="290" y1="102" x2="290" y2="122" stroke="#000" stroke-width="2.5"/>
  <polygon points="285,118 290,130 295,118" fill="#000"/>

  <!-- Step 2 -->
  <rect x="40" y="130" width="500" height="52" rx="6" fill="none" stroke="#000" stroke-width="3"/>
  <text x="56" y="152" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Step 2 — Halve the coefficient of x, then square it:</text>
  <text x="56" y="172" font-family="Georgia,serif" font-size="13" fill="#000">b/2 = 6/2 = 3      (b/2)² = 9</text>

  <!-- Arrow -->
  <line x1="290" y1="182" x2="290" y2="202" stroke="#000" stroke-width="2.5"/>
  <polygon points="285,198 290,210 295,198" fill="#000"/>

  <!-- Step 3 -->
  <rect x="40" y="210" width="500" height="52" rx="6" fill="none" stroke="#000" stroke-width="3"/>
  <text x="56" y="232" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Step 3 — Add and subtract (b/2)² inside expression:</text>
  <text x="56" y="252" font-family="Georgia,serif" font-size="13" fill="#000">y  =  (x² + 6x + 9)  −  9  +  2</text>

  <!-- Arrow -->
  <line x1="290" y1="262" x2="290" y2="282" stroke="#000" stroke-width="2.5"/>
  <polygon points="285,278 290,290 295,278" fill="#000"/>

  <!-- Step 4 -->
  <rect x="40" y="290" width="500" height="52" rx="6" fill="none" stroke="#000" stroke-width="3"/>
  <text x="56" y="312" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Step 4 — Factor the perfect square trinomial:</text>
  <text x="56" y="332" font-family="Georgia,serif" font-size="13" fill="#000">y  =  (x + 3)²  −  7</text>

  <!-- Arrow -->
  <line x1="290" y1="342" x2="290" y2="362" stroke="#000" stroke-width="2.5"/>
  <polygon points="285,358 290,370 295,358" fill="#000"/>

  <!-- Result box -->
  <rect x="40" y="370" width="500" height="80" rx="6" fill="none" stroke="#000" stroke-width="4"/>
  <text x="56" y="392" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Vertex Form:  y = a(x − h)² + k</text>
  <text x="56" y="412" font-family="Georgia,serif" font-size="13" fill="#000">y  =  (x − (−3))²  +  (−7)</text>
  <text x="56" y="432" font-family="Georgia,serif" font-size="12" fill="#000">→  vertex at  (h, k) = (−3, −7)    a = 1 &gt; 0 → opens upward</text>

  <!-- Brace annotations on step 4 -->
  <path d="M200,332 L200,345 L290,345 L290,332" fill="none" stroke="#000" stroke-width="2"/>
  <text x="218" y="358" font-family="Georgia,serif" font-size="9" fill="#000">perfect square</text>
</svg>`;

  // ─── 6. QUADRATIC FORMULA ──────────────────────────────────────────────────
  static quadraticFormulaDiscriminantRootsDerivationDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="700px" height="500px" viewBox="0 0 580 480">

  <text x="130" y="24" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Quadratic Formula — Discriminant &amp; Roots</text>

  <!-- Main formula box -->
  <rect x="100" y="42" width="380" height="60" rx="8" fill="none" stroke="#000" stroke-width="4"/>
  <text x="120" y="68" font-family="Georgia,serif" font-size="18" font-weight="bold" fill="#000">x  =  −b ± √(b² − 4ac)</text>
  <line x1="120" y1="72" x2="460" y2="72" stroke="#000" stroke-width="3"/>
  <text x="258" y="92" font-family="Georgia,serif" font-size="18" font-weight="bold" fill="#000">2a</text>

  <!-- Discriminant annotation with brace -->
  <text x="56" y="135" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">Discriminant:  Δ = b² − 4ac</text>

  <!-- Three cases box -->
  <rect x="40" y="155" width="500" height="150" rx="6" fill="none" stroke="#000" stroke-width="3"/>

  <!-- Case 1 -->
  <line x1="40" y1="205" x2="540" y2="205" stroke="#000" stroke-width="1.5" stroke-dasharray="5,4"/>
  <line x1="40" y1="255" x2="540" y2="255" stroke="#000" stroke-width="1.5" stroke-dasharray="5,4"/>

  <text x="56" y="178" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Δ &gt; 0</text>
  <text x="130" y="178" font-family="Georgia,serif" font-size="12" fill="#000">Two distinct real roots</text>
  <text x="130" y="196" font-family="Georgia,serif" font-size="11" fill="#000">Parabola crosses x-axis at two points</text>

  <text x="56" y="228" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Δ = 0</text>
  <text x="130" y="228" font-family="Georgia,serif" font-size="12" fill="#000">One repeated real root  (x = −b/2a)</text>
  <text x="130" y="246" font-family="Georgia,serif" font-size="11" fill="#000">Parabola is tangent to x-axis at vertex</text>

  <text x="56" y="278" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Δ &lt; 0</text>
  <text x="130" y="278" font-family="Georgia,serif" font-size="12" fill="#000">No real roots — two complex conjugates</text>
  <text x="130" y="296" font-family="Georgia,serif" font-size="11" fill="#000">Parabola does not cross x-axis</text>

  <!-- Derivation steps -->
  <text x="40" y="330" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Derivation by completing the square from ax² + bx + c = 0:</text>
  <text x="40" y="352" font-family="Georgia,serif" font-size="11" fill="#000">ax² + bx = −c   →   x² + (b/a)x = −c/a   →   (x + b/2a)² = (b²−4ac)/4a²</text>
  <text x="40" y="374" font-family="Georgia,serif" font-size="11" fill="#000">→   x + b/2a = ±√(b²−4ac) / 2a   →   x = (−b ± √Δ) / 2a</text>

  <!-- Worked example -->
  <rect x="40" y="392" width="500" height="72" rx="6" fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="5,3"/>
  <text x="56" y="412" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Example:  x² − 5x + 6 = 0   (a=1, b=−5, c=6)</text>
  <text x="56" y="432" font-family="Georgia,serif" font-size="11" fill="#000">Δ = 25 − 24 = 1 &gt; 0   →   x = (5 ± 1)/2</text>
  <text x="56" y="452" font-family="Georgia,serif" font-size="11" fill="#000">x = 3   or   x = 2   ✓</text>
</svg>`;

