  <!-- 4 rectangles: Δx=0.5, right endpoint heights: f(0.5)=0.25, f(1)=1, f(1.5)=2.25, f(2)=4 -->
  <!-- Rect 1: x=0 to 0.5, height=f(0.5)=0.25 → 20px. (80,340) to (130,320) -->
