  <!-- Chord AB -->
  <!-- A at 210° → (240+160cos210, 240−160sin210) = (240−138.6, 240+80) = (101, 320) -->
  <!-- B at 330° → (240+138.6, 240+80) = (379, 320) -->
  <line x1="101" y1="320" x2="379" y2="320" stroke="#000" stroke-width="3"/>
