  // ─── 8. FOUR-TERM GROUPING MODEL ──────────────────────────────────────────
  // Shows the grouping method for 4-term expressions:
  //   • bracket the pairs, factor each pair, extract common binomial factor
  static fourTermGroupingModelDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="380px" viewBox="0 0 680 340">

  <!-- Title -->
  <text x="160" y="24" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Four-Term Grouping Method</text>
  <text x="90" y="42" font-family="Georgia,serif" font-size="10" fill="#444">ax + ay + bx + by  →  group pairs  →  factor each  →  common binomial factor</text>

  <!-- Original expression -->
  <text x="30" y="72" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">Example:  x³ + 2x² + 3x + 6</text>

  <!-- Step 1: Group pairs -->
  <rect x="30" y="88" width="600" height="44" rx="5" fill="none" stroke="#000" stroke-width="2"/>
  <text x="42" y="107" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Step 1 — Group into pairs:</text>
  <text x="42" y="124" font-family="Georgia,serif" font-size="13" font-style="italic" fill="#000">(x³ + 2x²)  +  (3x + 6)</text>

  <!-- Underbrace pair 1 -->
  <path d="M42,130 L42,138 L140,138 L140,130" fill="none" stroke="#000" stroke-width="2"/>
  <text x="72" y="150" font-family="Georgia,serif" font-size="9" fill="#000">Pair 1</text>
  <!-- Underbrace pair 2 -->
  <path d="M198,130 L198,138 L280,138 L280,130" fill="none" stroke="#000" stroke-width="2"/>
  <text x="220" y="150" font-family="Georgia,serif" font-size="9" fill="#000">Pair 2</text>

  <!-- Step 2: Factor each pair -->
  <rect x="30" y="160" width="600" height="44" rx="5" fill="none" stroke="#000" stroke-width="2"/>
  <text x="42" y="179" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Step 2 — Factor each pair:</text>
  <text x="42" y="196" font-family="Georgia,serif" font-size="13" font-style="italic" fill="#000">x²(x + 2)  +  3(x + 2)</text>

  <!-- Arrow showing common factor -->
  <path d="M100,196 C100,218 220,218 220,196" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="4,3"/>
  <text x="136" y="228" font-family="Georgia,serif" font-size="9" fill="#000">same binomial</text>
  <path d="M260,196 C260,218 310,218 310,196" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="4,3"/>
  <text x="264" y="228" font-family="Georgia,serif" font-size="9" fill="#000">same</text>

  <!-- Step 3: Extract common binomial -->
  <rect x="30" y="238" width="600" height="44" rx="5" fill="none" stroke="#000" stroke-width="3"/>
  <text x="42" y="257" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Step 3 — Extract common binomial factor:</text>
  <text x="42" y="274" font-family="Georgia,serif" font-size="15" font-weight="bold" font-style="italic" fill="#000">(x + 2)(x² + 3)</text>

  <!-- Bracket labels -->
  <text x="42" y="294" font-family="Georgia,serif" font-size="9" fill="#555">↑ the repeated binomial becomes one factor</text>
  <text x="160" y="294" font-family="Georgia,serif" font-size="9" fill="#555">↑ the two outer factors combine</text>

  <!-- Side rule box -->
  <rect x="30" y="308" width="600" height="28" rx="4" fill="none" stroke="#000" stroke-width="1.5" stroke-dasharray="5,3"/>
  <text x="44" y="326" font-family="Georgia,serif" font-size="10" fill="#000">Rule: if after Step 2 the binomials in brackets are identical → factoring by grouping works ✓</text>
</svg>`;

