  // ─── 25. PST THREE-CONDITION CHECKLIST ────────────────────────────────────
  // Checklist format for perfect square trinomial recognition:
  static pstThreeConditionChecklistDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="420px" viewBox="0 0 680 380">

  <!-- Title -->
  <text x="140" y="24" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">PST — Three-Condition Verification Checklist</text>
  <text x="90" y="42" font-family="Georgia,serif" font-size="10" fill="#444">Apply to any trinomial Ax²+Bx+C — all three must hold for PST factorisation</text>

  <!-- Worked example header -->
  <text x="30" y="68" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Test:  4x² − 12x + 9</text>

  <!-- Condition rows -->
  <!-- C1 -->
  <rect x="30" y="80" width="600" height="68" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <rect x="30" y="80" width="56" height="68" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="38" y="122" font-family="Georgia,serif" font-size="30" fill="#000">✓</text>
  <text x="96" y="104" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Condition 1: First term is a perfect square</text>
  <text x="96" y="124" font-family="Georgia,serif" font-size="11" fill="#000">4x²  →  √(4x²) = 2x  ✓ (both 4 and x² are perfect squares)</text>
  <text x="96" y="140" font-family="Georgia,serif" font-size="9" fill="#555">A = 4 = 2²,  variable part = x² = (x)² — passes</text>

  <!-- C2 -->
  <rect x="30" y="162" width="600" height="68" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <rect x="30" y="162" width="56" height="68" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="38" y="204" font-family="Georgia,serif" font-size="30" fill="#000">✓</text>
  <text x="96" y="186" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Condition 2: Last term is a positive perfect square</text>
  <text x="96" y="206" font-family="Georgia,serif" font-size="11" fill="#000">9  →  √9 = 3  ✓ (positive integer, perfect square)</text>
  <text x="96" y="222" font-family="Georgia,serif" font-size="9" fill="#555">C = +9 = 3² — passes (if C were negative, would fail here)</text>

  <!-- C3 -->
  <rect x="30" y="244" width="600" height="68" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <rect x="30" y="244" width="56" height="68" rx="5" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="38" y="286" font-family="Georgia,serif" font-size="30" fill="#000">✓</text>
  <text x="96" y="268" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Condition 3: Middle = ±2·√(first)·√(last)</text>
  <text x="96" y="288" font-family="Georgia,serif" font-size="11" fill="#000">2 × 2x × 3 = 12x  →  middle is −12x  ✓  (magnitude matches, sign = negative)</text>
  <text x="96" y="304" font-family="Georgia,serif" font-size="9" fill="#555">|B| = 12 = 2×2×3 — passes; negative sign → (A−B)² form</text>

  <!-- Conclusion -->
  <rect x="30" y="328" width="600" height="44" rx="5" fill="none" stroke="#000" stroke-width="3"/>
  <text x="44" y="348" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Conclusion: All 3 conditions pass →  4x²−12x+9  is a PST</text>
  <text x="44" y="364" font-family="Georgia,serif" font-size="13" font-style="italic" fill="#000">  = (2x − 3)²</text>
</svg>`;

  // ─── 26. PST FACTORED FORM DIAGRAM ────────────────────────────────────────
  // Shows the two PST factored forms with annotation:
  static pstFactoredFormDiagramDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="380px" viewBox="0 0 680 340">

  <!-- Title -->
  <text x="160" y="24" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">PST Factored Form — Two Patterns</text>
  <text x="90" y="42" font-family="Georgia,serif" font-size="10" fill="#444">Perfect square trinomials always collapse to a single repeated binomial factor</text>

  <!-- Pattern 1: positive middle -->
  <rect x="30" y="58" width="290" height="200" rx="6" fill="none" stroke="#000" stroke-width="3"/>
  <text x="42" y="80" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Pattern 1 — Positive Middle Term</text>
  <line x1="30" y1="88" x2="320" y2="88" stroke="#000" stroke-width="1.5"/>
  <text x="80" y="118" font-family="Georgia,serif" font-size="18" font-style="italic" fill="#000">A² + 2AB + B²</text>
  <text x="120" y="148" font-family="Georgia,serif" font-size="18" fill="#000">=</text>
  <text x="80" y="178" font-family="Georgia,serif" font-size="20" font-weight="bold" font-style="italic" fill="#000">(A + B)²</text>

  <!-- Bracket pointing to A and B -->
  <text x="42" y="212" font-family="Georgia,serif" font-size="10" fill="#555">A = √(first term)</text>
  <text x="42" y="228" font-family="Georgia,serif" font-size="10" fill="#555">B = √(last term)</text>
  <text x="42" y="248" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">e.g. x²+6x+9 = (x+3)²</text>

  <!-- Pattern 2: negative middle -->
  <rect x="360" y="58" width="290" height="200" rx="6" fill="none" stroke="#000" stroke-width="3"/>
  <text x="372" y="80" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Pattern 2 — Negative Middle Term</text>
  <line x1="360" y1="88" x2="650" y2="88" stroke="#000" stroke-width="1.5"/>
  <text x="410" y="118" font-family="Georgia,serif" font-size="18" font-style="italic" fill="#000">A² − 2AB + B²</text>
  <text x="450" y="148" font-family="Georgia,serif" font-size="18" fill="#000">=</text>
  <text x="410" y="178" font-family="Georgia,serif" font-size="20" font-weight="bold" font-style="italic" fill="#000">(A − B)²</text>
  <text x="372" y="212" font-family="Georgia,serif" font-size="10" fill="#555">A = √(first term)</text>
  <text x="372" y="228" font-family="Georgia,serif" font-size="10" fill="#555">B = √(last term)</text>
  <text x="372" y="248" font-family="Georgia,serif" font-size="10" font-weight="bold" fill="#000">e.g. x²−10x+25 = (x−5)²</text>

  <!-- Key property note -->
  <rect x="30" y="272" width="620" height="60" rx="5" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="5,3"/>
  <text x="44" y="294" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Key property — double root:</text>
  <text x="44" y="312" font-family="Georgia,serif" font-size="11" fill="#000">Both patterns give ONE unique solution (double root): x = −B/A for (+) form, x = +B/A for (−) form</text>
  <text x="44" y="328" font-family="Georgia,serif" font-size="10" fill="#555">Graphically: parabola just touches x-axis at one point (vertex on axis) — tangent, not crossing</text>
</svg>`;

