  // ─── 32. DISTRIBUTIVE LAW REVERSAL ────────────────────────────────────────
  // Diagram showing factorisation as the reverse of the distributive law
  static distributiveLawReversalsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="480px" viewBox="0 0 580 480">

  <!-- Title -->
  <text x="80" y="28" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Distributive Law — Forward &amp; Reversal (Factorisation)</text>

  <!-- Forward direction: Expanding -->
  <text x="20" y="65" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">EXPANDING (Distributive Law → forward):</text>

  <text x="40" y="100" font-family="Georgia,serif" font-size="20" fill="#000">a(b + c)  =  ab + ac</text>

  <!-- Arrow labels -->
  <path d="M60,110 C60,145 200,155 200,150" fill="none" stroke="#000" stroke-width="2"/>
  <polygon points="196,145 204,155 210,145" fill="#000"/>
  <text x="60" y="140" font-family="Georgia,serif" font-size="10" fill="#555">a × b</text>

  <path d="M80,110 C80,160 295,155 295,150" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="5,3"/>
  <polygon points="291,145 299,155 305,145" fill="#000"/>
  <text x="100" y="155" font-family="Georgia,serif" font-size="10" fill="#555">a × c</text>

  <!-- Divider with bidirectional arrow -->
  <line x1="20" y1="180" x2="560" y2="180" stroke="#000" stroke-width="1.5" stroke-dasharray="6,4"/>
  <text x="240" y="175" font-family="Georgia,serif" font-size="11" fill="#000">←  reversible  →</text>

  <!-- Reverse direction: Factorising -->
  <text x="20" y="210" font-family="Georgia,serif" font-size="13" font-weight="bold" fill="#000">FACTORISING (Reversal → find common factor):</text>

  <text x="40" y="248" font-family="Georgia,serif" font-size="20" fill="#000">ab + ac  =  a(b + c)</text>

  <!-- Step-by-step factorising box -->
  <rect x="20" y="270" width="540" height="100" rx="5" fill="none" stroke="#000" stroke-width="2"/>
  <text x="30" y="292" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Method — Factorising ab + ac:</text>
  <line x1="20" y1="298" x2="560" y2="298" stroke="#000" stroke-width="1.2"/>
  <text x="30" y="316" font-family="Georgia,serif" font-size="12" fill="#000">1. Identify common factor: both terms have factor  a</text>
  <text x="30" y="334" font-family="Georgia,serif" font-size="12" fill="#000">2. Divide each term: ab÷a = b,   ac÷a = c</text>
  <text x="30" y="352" font-family="Georgia,serif" font-size="12" fill="#000">3. Write factored form: a(b + c)       ← place common factor outside bracket</text>
  <text x="30" y="364" font-family="Georgia,serif" font-size="11" fill="#555">   Verify: expand a(b+c) → ab+ac ✓</text>

  <!-- Numeric examples -->
  <rect x="20" y="382" width="540" height="88" rx="5" fill="none" stroke="#000" stroke-width="2" stroke-dasharray="6,3"/>
  <text x="30" y="402" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">Numeric Examples:</text>
  <line x1="20" y1="408" x2="560" y2="408" stroke="#000" stroke-width="1.2"/>
  <text x="30" y="424" font-family="Georgia,serif" font-size="12" fill="#000">6x + 9   =  3(2x + 3)       ← HCF of 6 and 9 is 3</text>
  <text x="30" y="442" font-family="Georgia,serif" font-size="12" fill="#000">12x² + 8x  =  4x(3x + 2)   ← HCF of 12x² and 8x is 4x</text>
  <text x="30" y="460" font-family="Georgia,serif" font-size="12" fill="#000">x(a+1) + y(a+1)  =  (a+1)(x + y)   ← bracket itself is common factor</text>
</svg>`;



