// ─── 25. KINEMATIC EQUATIONS DIAGRAM ──────────────────────────────────────
static kinematicEquationsDiagramsvg = `<?xml version="1.0" encoding="utf-8"?>
<svg version="1.1" xmlns="http://www.w3.org/2000/svg"
     width="800px" height="800px" viewBox="0 0 560 460">

  <!-- Title -->
  <text x="80" y="22" font-family="Georgia,serif" font-size="14" font-weight="bold" fill="#000">Kinematic Equations — Uniform Acceleration</text>
  <text x="50" y="38" font-family="Georgia,serif" font-size="10" fill="#333">Variables: v=final velocity, u=initial velocity, a=acceleration, s=displacement, t=time</text>

  <!-- ══ Velocity-time graph ══ -->
  <!-- Axes -->
  <line x1="50" y1="260" x2="330" y2="260" stroke="#000" stroke-width="2.5"/>
  <polygon points="326,255 338,260 326,265" fill="#000"/>
  <text x="342" y="264" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">t</text>
  <line x1="50" y1="260" x2="50" y2="80" stroke="#000" stroke-width="2.5"/>
  <polygon points="45,84 50,72 55,84" fill="#000"/>
  <text x="54" y="70" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">v</text>

  <!-- Grid -->
  <line x1="50" y1="220" x2="330" y2="220" stroke="#ddd" stroke-width="1"/>
  <line x1="50" y1="180" x2="330" y2="180" stroke="#ddd" stroke-width="1"/>
  <line x1="50" y1="140" x2="330" y2="140" stroke="#ddd" stroke-width="1"/>
  <line x1="50" y1="100" x2="330" y2="100" stroke="#ddd" stroke-width="1"/>

  <!-- Trapezoid: u at t=0, v at t=T -->
  <!-- v=u+at line: u=60→py=260−60=200. v=140→py=260−140=120. t goes from 0→280px -->
  <line x1="50" y1="200" x2="310" y2="120" stroke="#000" stroke-width="3.5" stroke-linecap="round"/>

  <!-- Trapezoid shading (displacement = area) using hatch -->
  <polygon points="50,200 310,120 310,260 50,260" fill="none" stroke="#000" stroke-width="2"/>
  <!-- Hatch lines inside trapezoid -->
  <line x1="80"  y1="260" x2="50"  y2="220" stroke="#000" stroke-width="1" stroke-dasharray="2,4"/>
  <line x1="110" y1="260" x2="50"  y2="193" stroke="#000" stroke-width="1" stroke-dasharray="2,4"/>
  <line x1="140" y1="260" x2="54"  y2="171" stroke="#000" stroke-width="1" stroke-dasharray="2,4"/>
  <line x1="170" y1="260" x2="80"  y2="157" stroke="#000" stroke-width="1" stroke-dasharray="2,4"/>
  <line x1="200" y1="260" x2="120" y2="148" stroke="#000" stroke-width="1" stroke-dasharray="2,4"/>
  <line x1="230" y1="260" x2="160" y2="138" stroke="#000" stroke-width="1" stroke-dasharray="2,4"/>
  <line x1="260" y1="260" x2="200" y2="128" stroke="#000" stroke-width="1" stroke-dasharray="2,4"/>
  <line x1="290" y1="260" x2="240" y2="120" stroke="#000" stroke-width="1" stroke-dasharray="2,4"/>
  <line x1="310" y1="250" x2="270" y2="120" stroke="#000" stroke-width="1" stroke-dasharray="2,4"/>

  <!-- Labels -->
  <text x="30" y="204" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">u</text>
  <text x="312" y="120" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">v</text>

  <!-- Acceleration (gradient) triangle -->
  <line x1="50" y1="200" x2="310" y2="200" stroke="#000" stroke-width="2" stroke-dasharray="4,3"/>
  <line x1="310" y1="200" x2="310" y2="120" stroke="#000" stroke-width="2" stroke-dasharray="4,3"/>
  <rect x="300" y="190" width="10" height="10" fill="none" stroke="#000" stroke-width="1.8"/>
  <text x="166" y="215" font-family="Georgia,serif" font-size="10" fill="#000">t (time)</text>
  <text x="314" y="162" font-family="Georgia,serif" font-size="10" fill="#000">v−u</text>
  <text x="55" y="100" font-family="Georgia,serif" font-size="10" fill="#000">Area = s</text>
  <text x="55" y="113" font-family="Georgia,serif" font-size="9" fill="#000">(displacement)</text>

  <!-- t-axis mark -->
  <line x1="310" y1="256" x2="310" y2="264" stroke="#000" stroke-width="2"/>
  <text x="306" y="276" font-family="Georgia,serif" font-size="10" fill="#000">t</text>

  <!-- ══ Four kinematic equations box ══ -->
  <rect x="358" y="65" width="190" height="200" rx="6" fill="none" stroke="#000" stroke-width="2.5"/>
  <text x="372" y="83" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">4 SUVAT Equations:</text>
  <line x1="362" y1="89" x2="544" y2="89" stroke="#000" stroke-width="1.5"/>
  <text x="368" y="108" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">① v = u + at</text>
  <text x="368" y="132" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">② s = ut + ½at²</text>
  <text x="368" y="156" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">③ v² = u² + 2as</text>
  <text x="368" y="180" font-family="Georgia,serif" font-size="12" font-weight="bold" fill="#000">④ s = ½(u+v)t</text>
  <line x1="362" y1="188" x2="544" y2="188" stroke="#000" stroke-width="1.2" stroke-dasharray="3,3"/>
  <text x="368" y="205" font-family="Georgia,serif" font-size="9" fill="#000">Missing var per equation:</text>
  <text x="368" y="218" font-family="Georgia,serif" font-size="9" fill="#000">① missing s</text>
  <text x="368" y="231" font-family="Georgia,serif" font-size="9" fill="#000">② missing v</text>
  <text x="368" y="244" font-family="Georgia,serif" font-size="9" fill="#000">③ missing t</text>
  <text x="368" y="257" font-family="Georgia,serif" font-size="9" fill="#000">④ missing a</text>

  <!-- ══ Worked example ══ -->
  <rect x="30" y="290" width="510" height="160" rx="6" fill="none" stroke="#000" stroke-width="2.5" stroke-dasharray="6,3"/>
  <text x="44" y="308" font-family="Georgia,serif" font-size="11" font-weight="bold" fill="#000">Worked Example: Car accelerates from u=10 m/s, a=3 m/s², for t=6 s. Find v and s.</text>
  <line x1="34" y1="314" x2="536" y2="314" stroke="#000" stroke-width="1.2"/>
  <text x="44" y="330" font-family="Georgia,serif" font-size="11" fill="#000">① v = u + at  = 10 + (3)(6) = 10 + 18 = 28 m/s</text>
  <text x="44" y="348" font-family="Georgia,serif" font-size="11" fill="#000">② s = ut + ½at² = 10(6) + ½(3)(36) = 60 + 54 = 114 m</text>
  <text x="44" y="366" font-family="Georgia,serif" font-size="11" fill="#000">③ Check: v² = u² + 2as = 100 + 2(3)(114) = 100 + 684 = 784 → v = 28 m/s ✓</text>
  <text x="44" y="384" font-family="Georgia,serif" font-size="11" fill="#000">④ Check: s = ½(u+v)t = ½(10+28)(6) = ½(38)(6) = 114 m ✓</text>
  <text x="44" y="406" font-family="Georgia,serif" font-size="10" fill="#000">Select the equation that contains the variable you want AND the variables you already know.</text>
  <text x="44" y="440" font-family="Georgia,serif" font-size="9" fill="#000">Note: equations valid only for constant (uniform) acceleration in a straight line.</text>
</svg>`;

