  <!-- x-axis ticks: π/2=140, π=220, 3π/2=300, 2π=380 (start x=60, scale 80/π*π/2=80px steps) -->
  <line x1="140" y1="166" x2="140" y2="174" stroke="#000" stroke-width="2"/>
